window.COMPLIANCE_REF = window.COMPLIANCE_REF || {};
window.COMPLIANCE_REF["iso"] = {"id": "iso", "version": "2022", "label": "ISO 27001:2022", "description": "S\u00e9curit\u00e9 de l'information, cybers\u00e9curit\u00e9 et protection de la vie priv\u00e9e \u2014 Information syst\u00e8me de management de la s\u00e9curit\u00e9 \u2014 Exigences", "description_en": "Information security, cybersecurity and privacy protection \u2014 Information security management systems \u2014 Requirements", "color": "#2563eb", "measures": [{"ref": "4.1", "theme": "Contexte de l'organisation", "theme_en": "Context of the organization", "mesure": "Compr\u00e9hension de l'organisation et de son contexte", "mesure_en": "Understanding the organization and its context", "description": "Identifier les facteurs internes et externes qui influencent la capacit\u00e9 de l\u2019organisation \u00e0 atteindre ses objectifs de s\u00e9curit\u00e9 de l\u2019information, en veillant \u00e0 ce que le SMSI soit align\u00e9 sur son contexte.", "description_en": "Identify internal and external factors that influence the organization\u2019s ability to achieve information security objectives, ensuring the ISMS is aligned with its context.", "linked_controls": ["doc.context"]}, {"ref": "4.2", "theme": "Contexte de l'organisation", "theme_en": "Context of the organization", "mesure": "Compr\u00e9hension des besoins et attentes des parties int\u00e9ress\u00e9es", "mesure_en": "Understanding the needs and expectations of interested parties", "description": "Analyser les besoins et attentes des parties int\u00e9ress\u00e9es pour les int\u00e9grer dans le SMSI et r\u00e9pondre aux exigences pertinentes en mati\u00e8re de s\u00e9curit\u00e9 de l\u2019information.", "description_en": "Analyze the needs and expectations of interested parties to incorporate them into the ISMS and address relevant information security requirements.", "linked_controls": ["doc.context"]}, {"ref": "4.3", "theme": "Contexte de l'organisation", "theme_en": "Context of the organization", "mesure": "D\u00e9termination du domaine d'application du syst\u00e8me de management de la s\u00e9curit\u00e9 de l'information", "mesure_en": "Determining the scope of the information security management system", "description": "D\u00e9finir le p\u00e9rim\u00e8tre du SMSI en prenant en compte les facteurs internes et externes, les besoins des parties prenantes et les d\u00e9pendances dans l\u2019environnement op\u00e9rationnel.", "description_en": "Define the scope of the ISMS by considering internal and external factors, stakeholder needs, and dependencies within the operational environment.", "linked_controls": ["doc.scope"]}, {"ref": "4.4", "theme": "Contexte de l'organisation", "theme_en": "Context of the organization", "mesure": "Syst\u00e8me de management de la s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security management system", "description": "Concevoir, exploiter et am\u00e9liorer en continu un SMSI pour g\u00e9rer efficacement les risques de s\u00e9curit\u00e9 de l\u2019information et atteindre les objectifs organisationnels.", "description_en": "Build, run, and continually improve an ISMS to effectively manage information security risks and meet organizational goals.", "linked_controls": ["doc.overview"]}, {"ref": "5.1", "theme": "Leadership", "theme_en": "Leadership", "mesure": "Leadership et engagement", "mesure_en": "Leadership and commitment", "description": "D\u00e9montrer un leadership et un engagement en soutenant le SMSI, en l'alignant sur les objectifs organisationnels, en allouant des ressources, en promouvant une culture de s\u00e9curit\u00e9 et en favorisant l'am\u00e9lioration continue.", "description_en": "Demonstrate leadership and commitment by supporting the ISMS, aligning it with organizational objectives, allocating resources, promoting a security culture, and driving continual improvement.", "linked_controls": ["doc.overview", "doc.controls", "doc.com", "doc.audit_plan", "doc.competency", "pol.main"]}, {"ref": "5.2", "theme": "Leadership", "theme_en": "Leadership", "mesure": "Politique", "mesure_en": "Policy", "description": "\u00c9tablir une politique de s\u00e9curit\u00e9 de l\u2019information align\u00e9e sur les objectifs et la direction strat\u00e9gique de l'organisation, pr\u00e9cisant les engagements en mati\u00e8re de conformit\u00e9, d'am\u00e9lioration continue et de promotion de la s\u00e9curit\u00e9 de l\u2019information.", "description_en": "Establish an information security policy aligned with the organization's objectives and strategic direction, outlining commitments to compliance, continual improvement, and the promotion of information security.", "linked_controls": ["pol.main"]}, {"ref": "5.3", "theme": "Leadership", "theme_en": "Leadership", "mesure": "R\u00f4les, responsabilit\u00e9s et autorit\u00e9s au sein de l'organisation", "mesure_en": "Organizational roles, responsibilities and authorities", "description": "D\u00e9finir, attribuer et communiquer les r\u00f4les, responsabilit\u00e9s et autorit\u00e9s pour assurer la mise en \u0153uvre et le fonctionnement efficaces du SMSI, avec une responsabilit\u00e9 align\u00e9e sur les objectifs organisationnels.", "description_en": "Define, assign, and communicate roles, responsibilities, and authorities to ensure the effective implementation and operation of the ISMS, with accountability aligned to organizational objectives.", "linked_controls": ["doc.raci"]}, {"ref": "6.1.1", "theme": "Actions \u00e0 mettre en oeuvre face aux risques et opportunit\u00e9s", "theme_en": "Actions to address risks and opportunities", "mesure": "G\u00e9n\u00e9ralit\u00e9s", "mesure_en": "General", "description": "\u00c9tablir un processus pour identifier les risques et opportunit\u00e9s en mati\u00e8re de s\u00e9curit\u00e9 de l\u2019information, en prenant en compte les facteurs internes et externes, les besoins des parties prenantes et les exigences applicables, afin d\u2019assurer que le SMSI atteigne ses objectifs.", "description_en": "Establish a process to identify information security risks and opportunities, considering internal and external factors, stakeholder needs, and applicable requirements to ensure the ISMS achieves its objectives.", "linked_controls": ["pol.risk", "doc.risk_register"]}, {"ref": "6.1.2", "theme": "Actions \u00e0 mettre en oeuvre face aux risques et opportunit\u00e9s", "theme_en": "Actions to address risks and opportunities", "mesure": "Appr\u00e9ciation des risques de s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security risk assessment requirement", "description": "\u00c9tablir un processus pour \u00e9valuer les risques li\u00e9s \u00e0 la s\u00e9curit\u00e9 de l\u2019information \u00e0 des intervalles planifi\u00e9s, en utilisant des crit\u00e8res d\u00e9finis pour \u00e9valuer les menaces sur la confidentialit\u00e9, l\u2019int\u00e9grit\u00e9 et la disponibilit\u00e9, garantissant des r\u00e9sultats coh\u00e9rents et fiables.", "description_en": "Establish a process to assess information security risks at planned intervals, using defined criteria to evaluate threats to confidentiality, integrity, and availability, ensuring consistent and reliable results.", "linked_controls": ["pol.risk", "doc.risk_register"]}, {"ref": "6.1.3", "theme": "Actions \u00e0 mettre en oeuvre face aux risques et opportunit\u00e9s", "theme_en": "Actions to address risks and opportunities", "mesure": "Traitement des risques de s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security risk treatment", "description": "D\u00e9finir un processus pour traiter les risques identifi\u00e9s en mati\u00e8re de s\u00e9curit\u00e9 de l\u2019information en s\u00e9lectionnant des contr\u00f4les appropri\u00e9s, en assurant leur alignement avec les crit\u00e8res d\u2019acceptation des risques et en les documentant dans un plan de traitement des risques.", "description_en": "Define a process to address identified information security risks by selecting appropriate controls, ensuring alignment with risk acceptance criteria, and documenting them in a risk treatment plan.", "linked_controls": ["pol.risk", "doc.risk_register", "doc.soa"]}, {"ref": "6.2", "theme": "Planification", "theme_en": "Planning", "mesure": "Objectifs de s\u00e9curit\u00e9 de l'information et plans pour les atteindre", "mesure_en": "Information security objectives and planning to achieve them", "description": "D\u00e9finir des objectifs mesurables en mati\u00e8re de s\u00e9curit\u00e9 de l\u2019information align\u00e9s sur le SMSI et les objectifs strat\u00e9giques, et planifier des actions d\u00e9taillant les responsabilit\u00e9s, les ressources, les \u00e9ch\u00e9ances et les m\u00e9thodes d\u2019\u00e9valuation pour les atteindre.", "description_en": "Set measurable information security objectives aligned with the ISMS and strategic goals, and plan actions detailing responsibilities, resources, timelines, and evaluation methods to achieve them.", "linked_controls": ["pol.main", "doc.so_register", "doc.risk_register", "doc.mgmt_review"]}, {"ref": "6.3", "theme": "Planification", "theme_en": "Planning", "mesure": "Planification des modifications", "mesure_en": "Planning for changes", "description": "Planifier les changements au SMSI de mani\u00e8re syst\u00e9matique pour garantir leur alignement avec les exigences de s\u00e9curit\u00e9 de l\u2019information, leur int\u00e9gration transparente dans les processus existants et une gestion efficace des risques.", "description_en": "Plan changes to the ISMS systematically to ensure alignment with information security requirements, seamless integration into existing processes, and effective risk management.", "linked_controls": ["pol.maintenance"]}, {"ref": "7.1", "theme": "Supports", "theme_en": "Support", "mesure": "Ressources", "mesure_en": "Resources", "description": "Fournir les ressources n\u00e9cessaires pour construire, exploiter et am\u00e9liorer en continu le SMSI, en garantissant son fonctionnement efficace et son alignement avec les objectifs organisationnels.", "description_en": "Provide the necessary resources to build, run, and continually improve the ISMS, ensuring its effective operation and alignment with organizational goals.", "linked_controls": ["doc.raci", "doc.competency", "doc.controls"]}, {"ref": "7.2", "theme": "Supports", "theme_en": "Support", "mesure": "Comp\u00e9tences", "mesure_en": "Competence", "description": "Garantir que le personnel impliqu\u00e9 dans le SMSI dispose des comp\u00e9tences n\u00e9cessaires gr\u00e2ce \u00e0 une formation, une \u00e9ducation ou une exp\u00e9rience appropri\u00e9es pour remplir efficacement leurs responsabilit\u00e9s.", "description_en": "Ensure personnel involved in the ISMS possess the necessary competence through appropriate education, training, or experience to fulfill their responsibilities effectively.", "linked_controls": ["pol.educ", "doc.educ_register"]}, {"ref": "7.3", "theme": "Supports", "theme_en": "Support", "mesure": "Sensibilisation", "mesure_en": "Awareness", "description": "Promouvoir la sensibilisation du personnel concern\u00e9 au SMSI, \u00e0 leur r\u00f4le dans la s\u00e9curit\u00e9 de l\u2019information et \u00e0 l\u2019importance de se conformer aux politiques et exigences de s\u00e9curit\u00e9.", "description_en": "Promote awareness among relevant personnel about the ISMS, their role in information security, and the importance of compliance with security policies and requirements.", "linked_controls": ["pol.educ", "doc.educ_register"]}, {"ref": "7.4", "theme": "Supports", "theme_en": "Support", "mesure": "Communication", "mesure_en": "Communication", "description": "\u00c9tablir des processus de communication internes et externes efficaces, assurant un \u00e9change d\u2019informations opportun et appropri\u00e9 en lien avec le SMSI et ses objectifs.", "description_en": "Establish effective internal and external communication processes, ensuring the timely and appropriate exchange of information relevant to the ISMS and its objectives.", "linked_controls": ["doc.com"]}, {"ref": "7.5.1", "theme": "Informations document\u00e9es", "theme_en": "Documented Information", "mesure": "G\u00e9n\u00e9ralit\u00e9s", "mesure_en": "General", "description": "Documenter le SMSI selon les besoins pour garantir une planification efficace, le fonctionnement, le contr\u00f4le des processus et l\u2019alignement avec les exigences organisationnelles.", "description_en": "Document the ISMS as needed to ensure effective planning, operation, control of processes, and alignment with organizational requirements.", "linked_controls": ["doc.doc_register"]}, {"ref": "7.5.2", "theme": "Informations document\u00e9es", "theme_en": "Documented Information", "mesure": "Cr\u00e9ation et mise \u00e0 jour", "mesure_en": "Creating and Updating documented information", "description": "S\u2019assurer que la documentation du SMSI est correctement cr\u00e9\u00e9e, mise \u00e0 jour et contr\u00f4l\u00e9e, y compris avec une approbation et une gestion des versions appropri\u00e9es.", "description_en": "Ensure ISMS documentation is appropriately created, updated, and controlled, including proper approval and version management.", "linked_controls": ["doc.doc_register"]}, {"ref": "7.5.3", "theme": "Informations document\u00e9es", "theme_en": "Documented Information", "mesure": "Contr\u00f4le des informations document\u00e9es", "mesure_en": "Control of documented information", "description": "Rendre la documentation du SMSI accessible et utilisable pour ceux qui en ont besoin, tout en la prot\u00e9geant contre tout acc\u00e8s non autoris\u00e9 ou perte.", "description_en": "Make ISMS documentation accessible and usable for those who need it, while protecting it from unauthorized access or loss.", "linked_controls": ["doc.doc_register"]}, {"ref": "8.1", "theme": "Fonctionnement", "theme_en": "Operations", "mesure": "Planification et contr\u00f4le op\u00e9rationnels", "mesure_en": "Operational planning and control", "description": "Planifier et contr\u00f4ler les processus du SMSI, en garantissant leur coh\u00e9rence avec les exigences et en apportant les ajustements n\u00e9cessaires pour traiter les risques et opportunit\u00e9s.", "description_en": "Plan and control ISMS processes, ensuring consistency with requirements and making necessary adjustments to address risks and opportunities.", "linked_controls": ["doc.raci", "doc.proc_register"]}, {"ref": "8.2", "theme": "Fonctionnement", "theme_en": "Operations", "mesure": "Appr\u00e9ciation des risques de s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security risk assessment", "description": "Mettre en \u0153uvre le processus d\u2019\u00e9valuation des risques pour identifier, \u00e9valuer et prioriser les risques li\u00e9s \u00e0 la s\u00e9curit\u00e9 de l\u2019information, tel que d\u00e9fini dans le cadre du SMSI.", "description_en": "Implement the risk assessment process to identify, evaluate, and prioritize information security risks as defined in the ISMS framework.", "linked_controls": ["doc.proc_register", "doc.risk_register"]}, {"ref": "8.3", "theme": "Fonctionnement", "theme_en": "Operations", "mesure": "Traitement des risques de s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security risk treatment", "description": "Appliquer le processus de traitement des risques en s\u00e9lectionnant et en mettant en \u0153uvre des contr\u00f4les appropri\u00e9s pour traiter les risques identifi\u00e9s, en assurant leur alignement avec les crit\u00e8res d\u2019acceptation des risques de l\u2019organisation.", "description_en": "Apply the risk treatment process by selecting and implementing appropriate controls to address identified risks, ensuring alignment with the organization\u2019s risk acceptance criteria.", "linked_controls": ["doc.proc_register", "doc.risk_register"]}, {"ref": "9.1", "theme": "\u00c9valuation de la performance", "theme_en": "Performance evaluation", "mesure": "Surveillance, mesurages, analyse et \u00e9valuation", "mesure_en": "Monitoring, measurement, analysis, evaluation", "description": "Surveiller, mesurer, analyser et \u00e9valuer la performance et l\u2019efficacit\u00e9 du SMSI en utilisant des m\u00e9thodes appropri\u00e9es align\u00e9es sur les objectifs de l\u2019organisation.", "description_en": "Monitor, measure, analyze, and evaluate the ISMS\u2019s performance and effectiveness using appropriate methods aligned with the organization\u2019s objectives.", "linked_controls": ["pol.monitor", "doc.audit_plan"]}, {"ref": "9.2.1", "theme": "Audit interne", "theme_en": "Internal audit", "mesure": "G\u00e9n\u00e9ralit\u00e9s", "mesure_en": "General", "description": "Effectuer des audits internes \u00e0 des intervalles planifi\u00e9s pour garantir que le SMSI est conforme aux exigences de l\u2019ISO/CEI 27001 et qu\u2019il est efficacement mis en \u0153uvre et maintenu.", "description_en": "Conduct internal audits at planned intervals to ensure the ISMS complies with ISO/IEC 27001 requirements and is effectively implemented and maintained.", "linked_controls": ["pol.audit"]}, {"ref": "9.2.2", "theme": "Audit interne", "theme_en": "Internal audit", "mesure": "Programme d'audit interne", "mesure_en": "Internal audit programme", "description": "Planifier et r\u00e9aliser des audits internes, y compris la d\u00e9finition des crit\u00e8res, du p\u00e9rim\u00e8tre, des m\u00e9thodes et des responsabilit\u00e9s, et rapporter les r\u00e9sultats \u00e0 la direction concern\u00e9e.", "description_en": "Plan and perform internal audits, including defining criteria, scope, methods, and responsibilities, and report the results to relevant management.", "linked_controls": ["doc.audit_plan"]}, {"ref": "9.3.1", "theme": "Revue de la direction", "theme_en": "Management review", "mesure": "G\u00e9n\u00e9ralit\u00e9s", "mesure_en": "General", "description": "Examiner le SMSI p\u00e9riodiquement pour s\u2019assurer de son ad\u00e9quation, de son efficacit\u00e9 et de sa capacit\u00e9 \u00e0 atteindre les objectifs organisationnels.", "description_en": "Review the ISMS periodically to ensure its suitability, adequacy, and effectiveness in achieving organizational objectives.", "linked_controls": ["pol.main"]}, {"ref": "9.3.2", "theme": "Revue de la direction", "theme_en": "Management review", "mesure": "El\u00e9ments d'entr\u00e9e de la revue de direction", "mesure_en": "Management review inputs", "description": "Inclure des \u00e9l\u00e9ments tels que les r\u00e9sultats d\u2019audits, la performance du SMSI, l\u2019\u00e9tat des risques, les opportunit\u00e9s d\u2019am\u00e9lioration et les changements n\u00e9cessaires dans la revue de direction.", "description_en": "Include inputs such as audit results, ISMS performance, risk status, improvement opportunities, and required changes in the management review.", "linked_controls": ["doc.mgmt_review"]}, {"ref": "9.3.3", "theme": "Revue de la direction", "theme_en": "Management review", "mesure": "R\u00e9sultats des revues de direction", "mesure_en": "Management review results", "description": "Documenter les r\u00e9sultats des revues de direction, y compris les d\u00e9cisions sur les am\u00e9liorations, les modifications du SMSI et les besoins en ressources.", "description_en": "Document the results of the management reviews, including decisions on improvements, ISMS changes, and resource requirements.", "linked_controls": ["doc.mgmt_review"]}, {"ref": "10.1", "theme": "Am\u00e9lioration", "theme_en": "Improvement", "mesure": "Am\u00e9lioration continue", "mesure_en": "Continual improvement", "description": "Identifier et agir sur les opportunit\u00e9s d\u2019am\u00e9lioration continue pour renforcer l\u2019efficacit\u00e9 du SMSI et son alignement avec les objectifs organisationnels.", "description_en": "Identify and act on opportunities for continual improvement to enhance the ISMS's effectiveness and alignment with organizational goals.", "linked_controls": ["pol.main"]}, {"ref": "10.2", "theme": "Am\u00e9lioration", "theme_en": "Improvement", "mesure": "Non-conformit\u00e9 et action corrective", "mesure_en": "Nonconformity and corrective action", "description": "Traiter les non-conformit\u00e9s en prenant des actions correctives, en identifiant les causes profondes et en mettant en \u0153uvre des mesures pour \u00e9viter leur r\u00e9currence, tout en documentant le processus.", "description_en": "Address nonconformities by taking corrective actions, identifying root causes, and implementing measures to prevent recurrence while documenting the process.", "linked_controls": ["pol.main", "pol.incident", "doc.nc_log", "doc.proc_register", "doc.raci", "doc.mgmt_review"]}, {"ref": "A.5.1", "theme": "", "theme_en": "", "mesure": "Politiques de s\u00e9curit\u00e9 de l'information", "mesure_en": "Policies for information security", "description": "Cette mesure de s\u00e9curit\u00e9 \u00e9tablit et maintient des politiques de s\u00e9curit\u00e9 de l'information align\u00e9es sur les objectifs organisationnels. Les mesures incluent la d\u00e9finition de la port\u00e9e, la fixation des objectifs et l'alignement avec les exigences de conformit\u00e9.", "description_en": "This control establishes and maintains information security policies aligned with organizational objectives. Measures include defining scope, setting goals, and ensuring alignment with compliance requirements.", "type": "organisationnel", "category": "policy"}, {"ref": "A.5.2", "theme": "", "theme_en": "", "mesure": "Fonctions et responsabilit\u00e9s li\u00e9es \u00e0 la s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security roles and responsibilities", "description": "Cette mesure de s\u00e9curit\u00e9 d\u00e9finit et attribue des r\u00f4les et responsabilit\u00e9s en mati\u00e8re de s\u00e9curit\u00e9 de l'information pour garantir la responsabilit\u00e9. Les mesures incluent une documentation claire des responsabilit\u00e9s, des revues p\u00e9riodiques et des m\u00e9canismes d'application.", "description_en": "This control defines and assigns roles and responsibilities for information security to ensure accountability. Measures include clear documentation of responsibilities, periodic reviews, and enforcement mechanisms.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.3", "theme": "", "theme_en": "", "mesure": "S\u00e9paration des t\u00e2ches", "mesure_en": "Segregation of duties", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la s\u00e9paration des t\u00e2ches pour r\u00e9duire le risque d'erreurs, de fraude et d'acc\u00e8s non autoris\u00e9. Les mesures incluent la s\u00e9paration des r\u00f4les, des restrictions d'acc\u00e8s et des audits r\u00e9guliers.", "description_en": "This control ensures segregation of duties to reduce the risk of errors, fraud, and unauthorized access. Measures include role separation, access restrictions, and regular audits.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.4", "theme": "", "theme_en": "", "mesure": "Responsabilit\u00e9s de la direction", "mesure_en": "Management responsibilities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les responsabilit\u00e9s de gestion en mati\u00e8re de s\u00e9curit\u00e9 de l'information sont clairement d\u00e9finies et mises en \u0153uvre. Les mesures incluent la fixation d'objectifs, l'allocation de ressources et la supervision de la conformit\u00e9.", "description_en": "This control ensures management responsibilities for information security are clearly defined and implemented. Measures include setting objectives, allocating resources, and overseeing compliance.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.5", "theme": "", "theme_en": "", "mesure": "Contact avec les autorit\u00e9s", "mesure_en": "Contact with authorities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit une communication rapide avec les autorit\u00e9s comp\u00e9tentes en cas d'incidents de s\u00e9curit\u00e9 de l'information. Les mesures incluent des protocoles de contact, des listes de contacts \u00e0 jour et l'attribution de responsabilit\u00e9s.", "description_en": "This control ensures timely communication with relevant authorities during information security incidents. Measures include establishing contact protocols, maintaining updated contact lists, and assigning responsibilities.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.6", "theme": "", "theme_en": "", "mesure": "Contact avec des groupes d'int\u00e9r\u00eat sp\u00e9cifiques", "mesure_en": "Contact with special interest groups", "description": "Cette mesure de s\u00e9curit\u00e9 facilite le contact avec des groupes d'int\u00e9r\u00eat pour rester inform\u00e9 des tendances et pratiques en mati\u00e8re de s\u00e9curit\u00e9. Les mesures incluent la participation \u00e0 des forums, des adh\u00e9sions et des initiatives collaboratives.", "description_en": "This control facilitates contact with special interest groups to stay informed about security trends and practices. Measures include participation in forums, memberships, and collaborative initiatives.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.7", "theme": "", "theme_en": "", "mesure": "Renseignements sur les menaces", "mesure_en": "Threat intelligence", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que des renseignements sur les menaces sont d\u00e9velopp\u00e9s et maintenus pour identifier et att\u00e9nuer les risques de s\u00e9curit\u00e9. Les mesures incluent le suivi des flux de menaces, l'analyse des tendances et le partage d'informations exploitables.", "description_en": "This control ensures threat intelligence is developed and maintained to identify and mitigate security risks. Measures include monitoring threat feeds, analyzing trends, and sharing actionable insights.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.8", "theme": "", "theme_en": "", "mesure": "S\u00e9curit\u00e9 de l'information dans la gestion de projet", "mesure_en": "Information security in project management", "description": "Cette mesure de s\u00e9curit\u00e9 int\u00e8gre la s\u00e9curit\u00e9 de l'information dans les pratiques de gestion de projet. Les mesures incluent les \u00e9valuations des risques, les revues de conformit\u00e9 et les points de contr\u00f4le de s\u00e9curit\u00e9 tout au long du cycle de vie du projet.", "description_en": "This control incorporates information security into project management practices. Measures include risk assessments, compliance reviews, and security checkpoints during project lifecycles.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.9", "theme": "", "theme_en": "", "mesure": "Inventaire des informations et autres actifs associ\u00e9s", "mesure_en": "Inventory of information and other associated assets", "description": "Cette mesure de s\u00e9curit\u00e9 garantit qu\u2019un inventaire pr\u00e9cis des informations et des actifs associ\u00e9s est maintenu. Les mesures incluent le suivi des actifs, des audits p\u00e9riodiques et une classification par sensibilit\u00e9.", "description_en": "This control ensures an accurate inventory of information and associated assets is maintained. Measures include asset tracking, periodic audits, and classification by sensitivity.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.10", "theme": "", "theme_en": "", "mesure": "Utilisation correcte des informations et autres actifs associ\u00e9s", "mesure_en": "Acceptable use of information and other associated assets", "description": "Cette mesure de s\u00e9curit\u00e9 d\u00e9finit les r\u00e8gles d'utilisation acceptable des informations et des actifs associ\u00e9s pour assurer une manipulation appropri\u00e9e. Les mesures incluent des politiques document\u00e9es, la formation des utilisateurs et des m\u00e9canismes d'application.", "description_en": "This control defines acceptable use of information and associated assets to ensure proper handling. Measures include documented policies, user training, and enforcement mechanisms.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.11", "theme": "", "theme_en": "", "mesure": "Restitution des actifs", "mesure_en": "Return of assets", "description": "Cette mesure de s\u00e9curit\u00e9 garantit le retour s\u00e9curis\u00e9 des actifs lorsque des employ\u00e9s ou des sous-traitants quittent ou changent de r\u00f4le. Les mesures incluent des listes de contr\u00f4le, le suivi des actifs et des protocoles de d\u00e9sactivation.", "description_en": "This control ensures the secure return of assets when employees or contractors leave or change roles. Measures include checklists, asset tracking, and decommissioning protocols.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.12", "theme": "", "theme_en": "", "mesure": "Classification des informations", "mesure_en": "Classification of information", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les informations sont class\u00e9es en fonction de leur sensibilit\u00e9 et de leur valeur pour assurer une protection ad\u00e9quate. Les mesures incluent des sch\u00e9mas de classification, des restrictions d'acc\u00e8s et des directives d'\u00e9tiquetage.", "description_en": "This control ensures information is classified based on its sensitivity and value to ensure appropriate protection. Measures include classification schemes, access restrictions, and labeling guidelines.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.13", "theme": "", "theme_en": "", "mesure": "Marquage des informations", "mesure_en": "Labelling of information", "description": "Cette mesure de s\u00e9curit\u00e9 garantit un \u00e9tiquetage coh\u00e9rent des informations pour refl\u00e9ter leur classification et leurs exigences de traitement. Les mesures incluent des mod\u00e8les standardis\u00e9s, des formations et des audits.", "description_en": "This control ensures consistent labeling of information to reflect its classification and handling requirements. Measures include standardized templates, training, and audits.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.14", "theme": "", "theme_en": "", "mesure": "Transfert des informations", "mesure_en": "Information transfer", "description": "Cette mesure de s\u00e9curit\u00e9 \u00e9tablit des processus s\u00e9curis\u00e9s pour le transfert d'informations entre syst\u00e8mes ou organisations. Les mesures incluent le chiffrement, les contr\u00f4les d'acc\u00e8s et les protocoles de transfert s\u00e9curis\u00e9s.", "description_en": "This control establishes secure processes for transferring information between systems or organizations. Measures include encryption, access controls, and secure transfer protocols.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.15", "theme": "", "theme_en": "", "mesure": "Contr\u00f4le d'acc\u00e8s", "mesure_en": "Access control", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre et maintient des m\u00e9canismes de contr\u00f4le d'acc\u00e8s pour limiter l'acc\u00e8s aux individus autoris\u00e9s. Les mesures incluent des contr\u00f4les bas\u00e9s sur les r\u00f4les, l'authentification multifacteur et des revues p\u00e9riodiques.", "description_en": "This control implements and maintains access control mechanisms to restrict access to authorized individuals. Measures include role-based access, multi-factor authentication, and periodic reviews.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.16", "theme": "", "theme_en": "", "mesure": "Gestion des identit\u00e9s", "mesure_en": "Identity management", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les identit\u00e9s sont g\u00e9r\u00e9es de mani\u00e8re s\u00e9curis\u00e9e pour garantir un acc\u00e8s pr\u00e9cis et fiable aux syst\u00e8mes. Les mesures incluent la v\u00e9rification d'identit\u00e9, la gestion du cycle de vie et l'approvisionnement des acc\u00e8s.", "description_en": "This control ensures identities are managed securely to guarantee accurate and reliable access to systems. Measures include identity verification, lifecycle management, and access provisioning.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.17", "theme": "", "theme_en": "", "mesure": "Informations d'authentification", "mesure_en": "Authentication information", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge les informations d'authentification, telles que les mots de passe, pour emp\u00eacher tout acc\u00e8s non autoris\u00e9. Les mesures incluent le chiffrement, le stockage s\u00e9curis\u00e9 et les mises \u00e0 jour p\u00e9riodiques des mots de passe.", "description_en": "This control protects authentication information, such as passwords, to prevent unauthorized access. Measures include encryption, secure storage, and periodic password updates.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.18", "theme": "", "theme_en": "", "mesure": "Droits d'acc\u00e8s", "mesure_en": "Access rights", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les droits d'acc\u00e8s sont r\u00e9guli\u00e8rement revus et g\u00e9r\u00e9s pour s'aligner sur les r\u00f4les et responsabilit\u00e9s. Les mesures incluent des audits p\u00e9riodiques, la r\u00e9vocation des acc\u00e8s et la gestion automatis\u00e9e des acc\u00e8s.", "description_en": "This control ensures access rights are regularly reviewed and managed to align with roles and responsibilities. Measures include periodic audits, access revocation, and automated access management.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.19", "theme": "", "theme_en": "", "mesure": "S\u00e9curit\u00e9 de l'information dans les relations avec les fournisseurs", "mesure_en": "Information security in supplier relationships", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que la s\u00e9curit\u00e9 de l'information est int\u00e9gr\u00e9e dans les relations et processus avec les fournisseurs. Les mesures incluent la diligence raisonnable, les revues de s\u00e9curit\u00e9 et la surveillance continue.", "description_en": "This control ensures information security is embedded in supplier relationships and processes. Measures include due diligence, security reviews, and ongoing monitoring.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.20", "theme": "", "theme_en": "", "mesure": "La s\u00e9curit\u00e9 de l'information dans les accords conclus avec les fournisseurs", "mesure_en": "Addressing information security within supplier agreements", "description": "Cette mesure de s\u00e9curit\u00e9 aborde les exigences de s\u00e9curit\u00e9 de l'information dans les accords avec les fournisseurs. Les mesures incluent des clauses contractuelles explicites, des audits de conformit\u00e9 et des p\u00e9nalit\u00e9s d\u00e9finies pour les violations.", "description_en": "This control addresses information security requirements within supplier agreements. Measures include explicit contract clauses, compliance audits, and defined penalties for violations.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.21", "theme": "", "theme_en": "", "mesure": "Gestion de la s\u00e9curit\u00e9 de l'information dans la cha\u00eene d'approvisionnement des technologies de l'information et de la communication (TIC)", "mesure_en": "Managing information security in the ICT supply chain", "description": "Cette mesure de s\u00e9curit\u00e9 g\u00e8re les risques de s\u00e9curit\u00e9 de l'information dans la cha\u00eene d'approvisionnement TIC pour garantir la s\u00e9curit\u00e9 des services et des composants. Les mesures incluent des \u00e9valuations des risques, des \u00e9valuations des fournisseurs et des protocoles de r\u00e9ponse aux incidents.", "description_en": "This control manages information security risks in the ICT supply chain to ensure security of services and components. Measures include risk assessments, supplier evaluations, and incident response protocols.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.22", "theme": "", "theme_en": "", "mesure": "Surveillance, r\u00e9vision et gestion des changements des services fournisseurs", "mesure_en": "Monitor, review and change management of supplier services", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les services des fournisseurs sont surveill\u00e9s, revus et ajust\u00e9s pour maintenir la s\u00e9curit\u00e9 de l'information. Les mesures incluent des accords de niveau de service, des revues p\u00e9riodiques et des mises \u00e0 jour contractuelles.", "description_en": "This control ensures supplier services are monitored, reviewed, and adjusted to maintain information security. Measures include service level agreements, periodic reviews, and contract updates.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.23", "theme": "", "theme_en": "", "mesure": "S\u00e9curit\u00e9 de l'information dans l'utilisation de services en nuage", "mesure_en": "Information security for use of cloud services", "description": "Cette mesure de s\u00e9curit\u00e9 garantit l'utilisation s\u00e9curis\u00e9e des services cloud en abordant les risques associ\u00e9s. Les mesures incluent le chiffrement des donn\u00e9es, les contr\u00f4les d'acc\u00e8s et les revues de conformit\u00e9 des fournisseurs.", "description_en": "This control ensures the secure use of cloud services by addressing associated risks. Measures include data encryption, access controls, and provider compliance reviews.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.24", "theme": "", "theme_en": "", "mesure": "Planification et pr\u00e9paration de la gestion des incidents de s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security incident management planning and preparation", "description": "Cette mesure de s\u00e9curit\u00e9 garantit une planification et une pr\u00e9paration ad\u00e9quates pour la gestion des incidents de s\u00e9curit\u00e9 de l'information. Les mesures incluent des plans de r\u00e9ponse aux incidents, des exercices de formation et des protocoles de communication.", "description_en": "This control ensures proper planning and preparation for managing information security incidents. Measures include incident response plans, training exercises, and communication protocols.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.25", "theme": "", "theme_en": "", "mesure": "\u00c9valuation des \u00e9v\u00e9nements de s\u00e9curit\u00e9 de l'information et prise de d\u00e9cision", "mesure_en": "Assessment and decision on information security events", "description": "Cette mesure de s\u00e9curit\u00e9 \u00e9tablit des processus pour \u00e9valuer et d\u00e9cider des actions li\u00e9es aux \u00e9v\u00e9nements de s\u00e9curit\u00e9 de l'information. Les mesures incluent l'analyse des causes profondes, l'\u00e9valuation des risques et des plans d'att\u00e9nuation.", "description_en": "This control establishes processes for assessing and deciding on actions related to information security events. Measures include root cause analysis, risk evaluation, and mitigation plans.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.26", "theme": "", "theme_en": "", "mesure": "R\u00e9ponse aux incidents de s\u00e9curit\u00e9 de l'information", "mesure_en": "Response to information security incidents", "description": "Cette mesure de s\u00e9curit\u00e9 garantit une r\u00e9ponse efficace aux incidents de s\u00e9curit\u00e9 de l'information pour minimiser l'impact et r\u00e9cup\u00e9rer rapidement. Les mesures incluent le signalement des incidents, des protocoles d'escalade et des strat\u00e9gies de confinement.", "description_en": "This control ensures effective response to information security incidents to minimize impact and recover quickly. Measures include incident reporting, escalation protocols, and containment strategies.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.27", "theme": "", "theme_en": "", "mesure": "Tirer des enseignements des incidents de s\u00e9curit\u00e9 de l'information", "mesure_en": "Learning from information security incidents", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les le\u00e7ons tir\u00e9es des incidents de s\u00e9curit\u00e9 de l'information sont document\u00e9es et mises en \u0153uvre pour am\u00e9liorer les processus. Les mesures incluent des revues post-incidents, des plans d'action et des mises \u00e0 jour des politiques.", "description_en": "This control ensures lessons learned from information security incidents are documented and implemented to improve processes. Measures include post-incident reviews, action plans, and policy updates.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.28", "theme": "", "theme_en": "", "mesure": "Collecte de preuves", "mesure_en": "Collection of evidence", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les preuves sont collect\u00e9es et conserv\u00e9es lors des incidents de s\u00e9curit\u00e9 pour soutenir les enqu\u00eates. Les mesures incluent des proc\u00e9dures de cha\u00eene de conservation, le stockage s\u00e9curis\u00e9 et les contr\u00f4les d'acc\u00e8s.", "description_en": "This control ensures evidence is collected and preserved during security incidents to support investigations. Measures include chain-of-custody procedures, secure storage, and access controls.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.29", "theme": "", "theme_en": "", "mesure": "S\u00e9curit\u00e9 de l'information pendant une perturbation", "mesure_en": "Information security during disruption", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que la s\u00e9curit\u00e9 de l'information est maintenue pendant les perturbations pour assurer la continuit\u00e9 des op\u00e9rations. Les mesures incluent des plans de contingence, des syst\u00e8mes de sauvegarde et des m\u00e9canismes de basculement.", "description_en": "This control ensures information security is maintained during disruptions to guarantee continuity of operations. Measures include contingency plans, backup systems, and failover mechanisms.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.30", "theme": "", "theme_en": "", "mesure": "Pr\u00e9paration des TIC la continuit\u00e9 d'activit\u00e9", "mesure_en": "ICT readiness for business continuity", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la pr\u00e9paration TIC pour la continuit\u00e9 des activit\u00e9s afin de minimiser les temps d'arr\u00eat pendant les perturbations. Les mesures incluent des tests de plans de reprise, des syst\u00e8mes redondants et des sites de reprise apr\u00e8s sinistre.", "description_en": "This control ensures ICT readiness for business continuity to minimize downtime during disruptions. Measures include testing recovery plans, redundant systems, and disaster recovery sites.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.31", "theme": "", "theme_en": "", "mesure": "Exigences l\u00e9gales, statutaires, r\u00e9glementaires et contractuelles", "mesure_en": "Legal, statutory, regulatory and contractual requirements", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la conformit\u00e9 aux exigences l\u00e9gales, r\u00e9glementaires et contractuelles en mati\u00e8re de s\u00e9curit\u00e9 de l'information. Les mesures incluent des revues de politiques, des audits et la documentation des preuves.", "description_en": "This control ensures compliance with legal, statutory, regulatory, and contractual information security requirements. Measures include policy reviews, audits, and evidence documentation.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.32", "theme": "", "theme_en": "", "mesure": "Droits de propri\u00e9t\u00e9 intellectuelle", "mesure_en": "Intellectual property rights", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la protection des droits de propri\u00e9t\u00e9 intellectuelle par des mesures de s\u00e9curit\u00e9 de l'information appropri\u00e9es. Les mesures incluent des restrictions d'acc\u00e8s, le chiffrement et des accords l\u00e9gaux.", "description_en": "This control ensures intellectual property rights are protected through appropriate information security measures. Measures include access restrictions, encryption, and legal agreements.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.33", "theme": "", "theme_en": "", "mesure": "Protection des enregistrements", "mesure_en": "Protection of records", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les enregistrements sont stock\u00e9s et prot\u00e9g\u00e9s de mani\u00e8re s\u00e9curis\u00e9e pour pr\u00e9venir toute perte ou acc\u00e8s non autoris\u00e9. Les mesures incluent des politiques de r\u00e9tention, un stockage s\u00e9curis\u00e9 et des contr\u00f4les d'acc\u00e8s.", "description_en": "This control ensures records are securely stored and protected to prevent loss or unauthorized access. Measures include retention policies, secure storage, and access controls.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.34", "theme": "", "theme_en": "", "mesure": "Protection de la vie priv\u00e9e et des donn\u00e9es \u00e0 caract\u00e8re personnel (DCP)", "mesure_en": "Privacy and protection of PII", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge la confidentialit\u00e9 et garantit le traitement s\u00e9curis\u00e9 des informations personnellement identifiables (PII). Les mesures incluent l'anonymisation, le chiffrement et la conformit\u00e9 aux lois sur la confidentialit\u00e9.", "description_en": "This control protects privacy and ensures the secure handling of personally identifiable information (PII). Measures include anonymization, encryption, and compliance with privacy laws.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.35", "theme": "", "theme_en": "", "mesure": "R\u00e9vision ind\u00e9pendante de la s\u00e9curit\u00e9 de l'information", "mesure_en": "Independent review of information security", "description": "Cette mesure de s\u00e9curit\u00e9 garantit des revues ind\u00e9pendantes de la s\u00e9curit\u00e9 de l'information pour \u00e9valuer l'efficacit\u00e9 et la conformit\u00e9. Les mesures incluent des audits externes, des \u00e9valuations des risques et des actions de suivi.", "description_en": "This control ensures independent reviews of information security to evaluate effectiveness and compliance. Measures include external audits, risk assessments, and follow-up actions.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.36", "theme": "", "theme_en": "", "mesure": "Conformit\u00e9 aux politiques, r\u00e8gles et normes de s\u00e9curit\u00e9 de l'information", "mesure_en": "Compliance with policies, rules and standards for information security", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la conformit\u00e9 \u00e0 toutes les politiques, r\u00e8gles et normes en mati\u00e8re de s\u00e9curit\u00e9 de l'information. Les mesures incluent des formations r\u00e9guli\u00e8res, des revues de politiques et des m\u00e9canismes d'application.", "description_en": "This control ensures compliance with all policies, rules, and standards for information security. Measures include regular training, policy reviews, and enforcement mechanisms.", "type": "organisationnel", "category": "process"}, {"ref": "A.5.37", "theme": "", "theme_en": "", "mesure": "Proc\u00e9dures d'exploitation document\u00e9es", "mesure_en": "Documented operating procedures", "description": "Cette mesure de s\u00e9curit\u00e9 d\u00e9veloppe et maintient des proc\u00e9dures op\u00e9rationnelles document\u00e9es pour garantir la coh\u00e9rence des pratiques de s\u00e9curit\u00e9. Les mesures incluent la documentation des processus, le contr\u00f4le des versions et l'accessibilit\u00e9.", "description_en": "This control develops and maintains documented operating procedures to ensure consistency in security practices. Measures include process documentation, version control, and accessibility.", "type": "organisationnel", "category": "process"}, {"ref": "A.6.1", "theme": "", "theme_en": "", "mesure": "S\u00e9lection des candidats", "mesure_en": "Screening", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la mise en \u0153uvre de processus de v\u00e9rification pour \u00e9valuer l'ad\u00e9quation des candidats avant leur embauche. Les mesures incluent des v\u00e9rifications des ant\u00e9c\u00e9dents, la v\u00e9rification d'identit\u00e9 et l'\u00e9valuation des qualifications pour r\u00e9duire les risques de s\u00e9curit\u00e9.", "description_en": "This control ensures the implementation of screening processes to verify the suitability of candidates before employment. Measures include background checks, identity verification, and assessment of qualifications to reduce security risks.", "type": "people", "category": "process"}, {"ref": "A.6.2", "theme": "", "theme_en": "", "mesure": "Termes et conditions du contrat de travail", "mesure_en": "Terms and conditions of employment", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les termes et conditions d'emploi incluent des responsabilit\u00e9s en mati\u00e8re de s\u00e9curit\u00e9 de l'information. Les mesures incluent des clauses explicites sur la confidentialit\u00e9, le respect des politiques et les cons\u00e9quences des violations.", "description_en": "This control ensures that terms and conditions of employment include information security responsibilities. Measures include explicit clauses about confidentiality, compliance with policies, and consequences for breaches.", "type": "people", "category": "process"}, {"ref": "A.6.3", "theme": "", "theme_en": "", "mesure": "Sensibilisation, enseignement et formation en s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security awareness, education and training", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les employ\u00e9s re\u00e7oivent une sensibilisation, une \u00e9ducation et une formation r\u00e9guli\u00e8res en mati\u00e8re de s\u00e9curit\u00e9 de l'information. Les mesures incluent des sessions de formation planifi\u00e9es, des programmes d'apprentissage en ligne et des exercices de phishing simul\u00e9s.", "description_en": "This control ensures that employees receive regular information security awareness, education, and training. Measures include scheduled training sessions, e-learning programs, and simulated phishing exercises.", "type": "people", "category": "process"}, {"ref": "A.6.4", "theme": "", "theme_en": "", "mesure": "Proc\u00e9dure disciplinaire", "mesure_en": "Disciplinary process", "description": "Cette mesure de s\u00e9curit\u00e9 \u00e9tablit un processus disciplinaire pour traiter les violations des politiques de s\u00e9curit\u00e9 de l'information. Les mesures incluent des lignes directrices claires, des proc\u00e9dures d'escalade et une application coh\u00e9rente pour maintenir la responsabilit\u00e9.", "description_en": "This control establishes a disciplinary process to address breaches of information security policies. Measures include clear guidelines, escalation procedures, and consistent enforcement to maintain accountability.", "type": "people", "category": "process"}, {"ref": "A.6.5", "theme": "", "theme_en": "", "mesure": "Responsabilit\u00e9s apr\u00e8s la fin ou le changement d'emploi", "mesure_en": "Responsibilities after termination or change of employment", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les responsabilit\u00e9s li\u00e9es \u00e0 la s\u00e9curit\u00e9 de l'information sont d\u00e9finies et appliqu\u00e9es apr\u00e8s la fin d\u2019un contrat ou un changement de r\u00f4le. Les mesures incluent la r\u00e9vocation des droits d'acc\u00e8s, la r\u00e9cup\u00e9ration des actifs de l'organisation et la r\u00e9alisation d'entretiens de sortie.", "description_en": "This control ensures that responsibilities related to information security are defined and enforced after termination or role changes. Measures include revoking access rights, collecting organizational assets, and conducting exit interviews.", "type": "people", "category": "process"}, {"ref": "A.6.6", "theme": "", "theme_en": "", "mesure": "Accords de confidentialit\u00e9 ou de non-divulgation", "mesure_en": "Confidentiality or non-disclosure agreements", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre des accords de confidentialit\u00e9 ou de non-divulgation pour prot\u00e9ger les informations sensibles. Les mesures incluent des accords sign\u00e9s au d\u00e9but de l'emploi, des rappels p\u00e9riodiques et l'application d'actions l\u00e9gales en cas de violations.", "description_en": "This control implements confidentiality or non-disclosure agreements to protect sensitive information. Measures include signed agreements at the start of employment, periodic reminders, and enforcement of legal actions in case of violations.", "type": "people", "category": "process"}, {"ref": "A.6.7", "theme": "", "theme_en": "", "mesure": "Travail \u00e0 distance", "mesure_en": "Remote working", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la gestion s\u00e9curis\u00e9e des risques li\u00e9s \u00e0 la s\u00e9curit\u00e9 de l'information pendant le t\u00e9l\u00e9travail. Les mesures incluent un acc\u00e8s s\u00e9curis\u00e9 aux syst\u00e8mes de l'entreprise, l'utilisation obligatoire de VPN et des politiques pour la gestion des donn\u00e9es sensibles \u00e0 distance.", "description_en": "This control ensures the secure management of information security risks during remote working. Measures include secure access to corporate systems, mandatory use of VPNs, and policies for handling sensitive data remotely.", "type": "people", "category": "process"}, {"ref": "A.6.8", "theme": "", "theme_en": "", "mesure": "D\u00e9claration des \u00e9v\u00e9nements de s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security event reporting", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les employ\u00e9s peuvent signaler rapidement les \u00e9v\u00e9nements de s\u00e9curit\u00e9 de l'information. Les mesures incluent des canaux de signalement d'incidents, des campagnes de sensibilisation et des proc\u00e9dures de suivi pour enqu\u00eater et traiter les \u00e9v\u00e9nements signal\u00e9s.", "description_en": "This control ensures employees can promptly report information security events. Measures include incident reporting channels, awareness campaigns, and follow-up procedures to investigate and address reported events.", "type": "people", "category": "process"}, {"ref": "A.7.1", "theme": "", "theme_en": "", "mesure": "P\u00e9rim\u00e8tres de s\u00e9curit\u00e9 physique", "mesure_en": "Physical security perimeters", "description": "Cette mesure de s\u00e9curit\u00e9 \u00e9tablit des p\u00e9rim\u00e8tres de s\u00e9curit\u00e9 physique pour prot\u00e9ger les zones critiques contre les acc\u00e8s non autoris\u00e9s. Les mesures incluent des barri\u00e8res, des contr\u00f4les d'acc\u00e8s et des syst\u00e8mes de surveillance pour garantir que seules les personnes autoris\u00e9es peuvent entrer.", "description_en": "This control establishes physical security perimeters to protect critical areas from unauthorized access. Measures include barriers, access controls, and monitoring systems to ensure only authorized individuals can enter.", "type": "physical", "category": "physical"}, {"ref": "A.7.2", "theme": "", "theme_en": "", "mesure": "Les entr\u00e9es physiques", "mesure_en": "Physical entry", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les points d'entr\u00e9e physiques sont contr\u00f4l\u00e9s et surveill\u00e9s pour emp\u00eacher les acc\u00e8s non autoris\u00e9s. Les mesures incluent des syst\u00e8mes de badges, du personnel de s\u00e9curit\u00e9 et des registres des visiteurs.", "description_en": "This control ensures physical entry points are controlled and monitored to prevent unauthorized access. Measures include badge systems, security personnel, and visitor logs.", "type": "physical", "category": "physical"}, {"ref": "A.7.3", "theme": "", "theme_en": "", "mesure": "S\u00e9curisation des bureaux, des salles et des installations", "mesure_en": "Securing offices, rooms and facilities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les bureaux, les pi\u00e8ces et les installations sont s\u00e9curis\u00e9s pour prot\u00e9ger les informations et les ressources. Les mesures incluent des portes verrouill\u00e9es, des zones restreintes et des syst\u00e8mes de surveillance.", "description_en": "This control ensures that offices, rooms, and facilities are secured to protect information and resources. Measures include locked doors, restricted areas, and surveillance systems.", "type": "physical", "category": "physical"}, {"ref": "A.7.4", "theme": "", "theme_en": "", "mesure": "Surveillance de la s\u00e9curit\u00e9 physique", "mesure_en": "Physical security monitoring", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre une surveillance de la s\u00e9curit\u00e9 physique pour d\u00e9tecter et r\u00e9pondre rapidement aux menaces. Les mesures incluent des syst\u00e8mes de vid\u00e9osurveillance, des d\u00e9tecteurs de mouvement et des alertes en temps r\u00e9el.", "description_en": "This control implements physical security monitoring to detect and respond promptly to threats. Measures include CCTV systems, motion detectors, and real-time alerts.", "type": "physical", "category": "physical"}, {"ref": "A.7.5", "theme": "", "theme_en": "", "mesure": "Protection contre les menaces physiques et environnementales", "mesure_en": "Protecting against physical and environmental threats", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge les syst\u00e8mes et les ressources contre les menaces physiques et environnementales. Les mesures incluent des syst\u00e8mes de suppression d'incendie, des contr\u00f4les de temp\u00e9rature et des barri\u00e8res anti-inondation.", "description_en": "This control protects systems and resources from physical and environmental threats. Measures include fire suppression systems, temperature controls, and flood prevention barriers.", "type": "physical", "category": "physical"}, {"ref": "A.7.6", "theme": "", "theme_en": "", "mesure": "Travail dans les zones s\u00e9curis\u00e9es", "mesure_en": "Working In secure areas", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les zones s\u00e9curis\u00e9es sont g\u00e9r\u00e9es pour permettre l'acc\u00e8s uniquement aux personnes autoris\u00e9es. Les mesures incluent des syst\u00e8mes de contr\u00f4le d'acc\u00e8s, des escortes pour visiteurs et la surveillance des activit\u00e9s.", "description_en": "This control ensures that secure areas are managed to allow authorized access only. Measures include access control systems, visitor escorts, and activity monitoring.", "type": "physical", "category": "physical"}, {"ref": "A.7.7", "theme": "", "theme_en": "", "mesure": "Bureau propre et \u00e9cran vide", "mesure_en": "Clear desk and clear screen", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les informations sensibles ne sont pas laiss\u00e9es expos\u00e9es en adoptant des politiques de bureau propre et d'\u00e9cran clair. Les mesures incluent le verrouillage des documents sensibles et le verrouillage automatique des \u00e9crans en cas d'inutilisation.", "description_en": "This control ensures sensitive information is not left exposed by adopting clear desk and clear screen policies. Measures include locking sensitive documents away and auto-locking screens when not in use.", "type": "physical", "category": "physical"}, {"ref": "A.7.8", "theme": "", "theme_en": "", "mesure": "Emplacement et protection du mat\u00e9riel", "mesure_en": "Equipment siting and protection", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les \u00e9quipements sont positionn\u00e9s et prot\u00e9g\u00e9s pour pr\u00e9venir les acc\u00e8s non autoris\u00e9s ou les dommages. Les mesures incluent des montages s\u00e9curis\u00e9s, des armoires verrouill\u00e9es et des zones d'acc\u00e8s restreintes.", "description_en": "This control ensures that equipment is positioned and protected to prevent unauthorized access or damage. Measures include secure mounting, locked cabinets, and restricted access areas.", "type": "physical", "category": "physical"}, {"ref": "A.7.9", "theme": "", "theme_en": "", "mesure": "S\u00e9curit\u00e9 des actifs hors des locaux", "mesure_en": "Security of assets off-premises", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les actifs utilis\u00e9s ou stock\u00e9s hors des locaux sont s\u00e9curis\u00e9s pour maintenir leur confidentialit\u00e9 et leur int\u00e9grit\u00e9. Les mesures incluent le chiffrement, le transport s\u00e9curis\u00e9 et le suivi des acc\u00e8s.", "description_en": "This control ensures assets used or stored off-premises are secured to maintain confidentiality and integrity. Measures include encryption, secure transport, and access tracking.", "type": "physical", "category": "physical"}, {"ref": "A.7.10", "theme": "", "theme_en": "", "mesure": "Supports de stockage", "mesure_en": "Storage media", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge les supports de stockage pour emp\u00eacher tout acc\u00e8s ou alt\u00e9ration non autoris\u00e9. Les mesures incluent le stockage s\u00e9curis\u00e9, le chiffrement et les restrictions d'acc\u00e8s.", "description_en": "This control safeguards storage media to prevent unauthorized access or tampering. Measures include secure storage, encryption, and access restrictions.", "type": "physical", "category": "physical"}, {"ref": "A.7.11", "theme": "", "theme_en": "", "mesure": "Services supports", "mesure_en": "Supporting utilities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les utilitaires de soutien, tels que les syst\u00e8mes d'alimentation et de refroidissement, sont fiables et prot\u00e9g\u00e9s contre les perturbations. Les mesures incluent des syst\u00e8mes redondants et une s\u00e9curit\u00e9 physique.", "description_en": "This control ensures that supporting utilities, such as power and cooling systems, are reliable and protected from disruptions. Measures include redundant systems and physical security.", "type": "physical", "category": "physical"}, {"ref": "A.7.12", "theme": "", "theme_en": "", "mesure": "S\u00e9curit\u00e9 du c\u00e2blage", "mesure_en": "Cabling security", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les c\u00e2bles sont s\u00e9curis\u00e9s pour pr\u00e9venir toute interception ou tout dommage non autoris\u00e9. Les mesures incluent des conduits de protection, un \u00e9tiquetage appropri\u00e9 et un routage s\u00e9curis\u00e9.", "description_en": "This control ensures that cables are secured to prevent unauthorized interception or damage. Measures include protective conduits, proper labeling, and secure routing.", "type": "physical", "category": "physical"}, {"ref": "A.7.13", "theme": "", "theme_en": "", "mesure": "Maintenance du mat\u00e9riel", "mesure_en": "Equipment maintenance", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les \u00e9quipements sont maintenus pour assurer leur bon fonctionnement et pr\u00e9venir les pannes. Les mesures incluent un entretien r\u00e9gulier, des pratiques de maintenance s\u00e9curis\u00e9es et un acc\u00e8s r\u00e9serv\u00e9 au personnel autoris\u00e9.", "description_en": "This control ensures that equipment is maintained to guarantee proper functioning and prevent failures. Measures include regular servicing, secure maintenance practices, and authorized personnel access.", "type": "physical", "category": "physical"}, {"ref": "A.7.14", "theme": "", "theme_en": "", "mesure": "\u00c9limination ou recyclage s\u00e9curis\u00e9(e) du mat\u00e9riel", "mesure_en": "Secure disposal or re-use of equipment", "description": "Cette mesure de s\u00e9curit\u00e9 garantit l'\u00e9limination ou la r\u00e9utilisation s\u00e9curis\u00e9e des \u00e9quipements pour prot\u00e9ger les informations sensibles. Les mesures incluent la d\u00e9sinfection des donn\u00e9es, la destruction physique et les processus de mise au rebut certifi\u00e9s.", "description_en": "This control ensures the secure disposal or reuse of equipment to protect sensitive information. Measures include data sanitization, physical destruction, and certified disposal processes.", "type": "physical", "category": "physical"}, {"ref": "A.8.1", "theme": "", "theme_en": "", "mesure": "Terminaux finaux des utilisateurs", "mesure_en": "User end point devices", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la protection des dispositifs de point de terminaison tels que les ordinateurs portables, de bureau et les appareils mobiles en mettant en \u0153uvre des mesures comme la d\u00e9tection des terminaux, le chiffrement et des configurations s\u00e9curis\u00e9es pour minimiser les risques.", "description_en": "This control ensures the protection of endpoint devices such as laptops, desktops, and mobile devices by implementing security measures like endpoint detection, encryption, and secure configurations to minimize risks.", "type": "technological", "category": "technical"}, {"ref": "A.8.2", "theme": "", "theme_en": "", "mesure": "Droits d'acc\u00e8s privil\u00e9gi\u00e9s", "mesure_en": "Privileged access rights", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les droits d'acc\u00e8s privil\u00e9gi\u00e9s sont accord\u00e9s, g\u00e9r\u00e9s et surveill\u00e9s avec soin pour pr\u00e9venir les abus et renforcer la s\u00e9curit\u00e9. Les mesures comprennent des contr\u00f4les d'acc\u00e8s bas\u00e9s sur les r\u00f4les, des revues p\u00e9riodiques et une gestion stricte des comptes.", "description_en": "This control ensures that privileged access rights are granted, managed, and monitored carefully to prevent misuse and enhance security. Measures include role-based access controls, periodic reviews, and strict account management.", "type": "technological", "category": "technical"}, {"ref": "A.8.3", "theme": "", "theme_en": "", "mesure": "Restriction d'acc\u00e8s aux informations", "mesure_en": "Information access restriction", "description": "Cette mesure de s\u00e9curit\u00e9 limite l'acc\u00e8s aux informations sensibles selon le principe du besoin d'en conna\u00eetre. Les mesures incluent l'authentification des utilisateurs, les permissions bas\u00e9es sur les r\u00f4les et des revues r\u00e9guli\u00e8res des acc\u00e8s.", "description_en": "This control restricts access to sensitive information based on need-to-know principles. Measures include user authentication, role-based permissions, and regular access reviews.", "type": "technological", "category": "technical"}, {"ref": "A.8.4", "theme": "", "theme_en": "", "mesure": "Acc\u00e8s aux codes source", "mesure_en": "Access to source code", "description": "Cette mesure de s\u00e9curit\u00e9 s\u00e9curise l'acc\u00e8s au code source en emp\u00eachant la visualisation, la modification ou l'exposition non autoris\u00e9es. Les mesures incluent le contr\u00f4le de version, les d\u00e9p\u00f4ts s\u00e9curis\u00e9s et l'acc\u00e8s restreint aux d\u00e9veloppeurs.", "description_en": "This control secures access to source code by preventing unauthorized viewing, modification, or exposure. Measures include version control, secure repositories, and restricted developer access.", "type": "technological", "category": "technical"}, {"ref": "A.8.5", "theme": "", "theme_en": "", "mesure": "Authentification s\u00e9curis\u00e9e", "mesure_en": "Secure authentication", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre des m\u00e9canismes d'authentification solides, tels que l'authentification multifacteur, pour v\u00e9rifier l'identit\u00e9 des utilisateurs et emp\u00eacher les acc\u00e8s non autoris\u00e9s.", "description_en": "This control implements strong authentication mechanisms, such as multi-factor authentication, to verify user identities and prevent unauthorized access.", "type": "technological", "category": "technical"}, {"ref": "A.8.6", "theme": "", "theme_en": "", "mesure": "Dimensionnement", "mesure_en": "Capacity management", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que la capacit\u00e9 des syst\u00e8mes est g\u00e9r\u00e9e pour assurer des performances ad\u00e9quates et \u00e9viter les perturbations. Les mesures incluent la surveillance de l'utilisation des ressources et la planification des besoins futurs.", "description_en": "This control ensures system capacity is managed to provide adequate performance and prevent disruptions. Measures include monitoring resource usage and planning for future needs.", "type": "technological", "category": "technical"}, {"ref": "A.8.7", "theme": "", "theme_en": "", "mesure": "Protection contre les programmes malveillants (malware)", "mesure_en": "Protection against malware", "description": "Cette mesure de s\u00e9curit\u00e9 d\u00e9ploie des mesures comme des logiciels antivirus, des outils de d\u00e9tection des menaces et des mises \u00e0 jour r\u00e9guli\u00e8res pour prot\u00e9ger les syst\u00e8mes contre les logiciels malveillants et les attaques.", "description_en": "This control deploys measures like antivirus software, threat detection tools, and regular updates to protect systems from malware and malicious attacks.", "type": "technological", "category": "technical"}, {"ref": "A.8.8", "theme": "", "theme_en": "", "mesure": "Gestion des vuln\u00e9rabilit\u00e9s techniques", "mesure_en": "Management of technical vulnerabilities", "description": "Cette mesure de s\u00e9curit\u00e9 identifie, \u00e9value et rem\u00e9die rapidement aux vuln\u00e9rabilit\u00e9s techniques pour minimiser les risques de s\u00e9curit\u00e9. Les mesures incluent les analyses de vuln\u00e9rabilit\u00e9s et la gestion des correctifs.", "description_en": "This control identifies, evaluates, and remediates technical vulnerabilities promptly to minimize security risks. Measures include vulnerability scanning and patch management.", "type": "technological", "category": "technical"}, {"ref": "A.8.9", "theme": "", "theme_en": "", "mesure": "Gestion des configurations", "mesure_en": "Configuration management", "description": "Cette mesure de s\u00e9curit\u00e9 garantit une gestion coh\u00e9rente des configurations des syst\u00e8mes pour maintenir des param\u00e8tres s\u00e9curis\u00e9s et pr\u00e9venir les changements non autoris\u00e9s.", "description_en": "This control ensures consistent management of system configurations to maintain security settings and prevent unauthorized changes.", "type": "technological", "category": "technical"}, {"ref": "A.8.10", "theme": "", "theme_en": "", "mesure": "Suppression des informations", "mesure_en": "Information deletion", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les informations sensibles sont supprim\u00e9es de mani\u00e8re s\u00e9curis\u00e9e lorsqu'elles ne sont plus n\u00e9cessaires pour \u00e9viter toute r\u00e9cup\u00e9ration ou exposition non autoris\u00e9e.", "description_en": "This control ensures sensitive information is securely deleted when no longer required to prevent unauthorized recovery or exposure.", "type": "technological", "category": "technical"}, {"ref": "A.8.11", "theme": "", "theme_en": "", "mesure": "Masquage des donn\u00e9es", "mesure_en": "Data masking", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge les informations sensibles lors de leur traitement ou affichage en utilisant des techniques de masquage des donn\u00e9es pour les rendre inaccessibles aux utilisateurs non autoris\u00e9s.", "description_en": "This control protects sensitive information during processing or display by using data masking techniques to obscure data from unauthorized users.", "type": "technological", "category": "technical"}, {"ref": "A.8.12", "theme": "", "theme_en": "", "mesure": "Pr\u00e9vention de la fuite de donn\u00e9es", "mesure_en": "Data leakage prevention", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre des m\u00e9canismes pour emp\u00eacher l'exposition accidentelle des donn\u00e9es sensibles via des e-mails, des supports amovibles ou d'autres canaux.", "description_en": "This control implements mechanisms to prevent the accidental exposure of sensitive data through email, removable media, or other channels.", "type": "technological", "category": "technical"}, {"ref": "A.8.13", "theme": "", "theme_en": "", "mesure": "Sauvegarde des informations", "mesure_en": "Information backup", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les informations critiques sont sauvegard\u00e9es r\u00e9guli\u00e8rement et en toute s\u00e9curit\u00e9 pour assurer leur disponibilit\u00e9 en cas d'incidents ou de catastrophes.", "description_en": "This control ensures critical information is backed up regularly and securely to ensure its availability in case of incidents or disasters.", "type": "technological", "category": "technical"}, {"ref": "A.8.14", "theme": "", "theme_en": "", "mesure": "Redondance des moyens de traitement de l'information", "mesure_en": "Redundancy of information processing facilities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que la redondance est int\u00e9gr\u00e9e dans les installations de traitement pour maintenir la disponibilit\u00e9 et les op\u00e9rations en cas de d\u00e9faillances ou d'urgences.", "description_en": "This control ensures redundancy is built into processing facilities to maintain availability and operations during system failures or emergencies.", "type": "technological", "category": "technical"}, {"ref": "A.8.15", "theme": "", "theme_en": "", "mesure": "Journalisation", "mesure_en": "Logging", "description": "Cette mesure de s\u00e9curit\u00e9 permet la journalisation des activit\u00e9s au sein des syst\u00e8mes pour soutenir la surveillance, la d\u00e9tection des incidents et les analyses forensiques.", "description_en": "This control enables logging of activities within systems to support monitoring, incident detection, and forensic investigations.", "type": "technological", "category": "technical"}, {"ref": "A.8.16", "theme": "", "theme_en": "", "mesure": "Activit\u00e9s de surveillance", "mesure_en": "Monitoring activities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la surveillance continue des activit\u00e9s du syst\u00e8me pour d\u00e9tecter, r\u00e9pondre et att\u00e9nuer les menaces \u00e0 la s\u00e9curit\u00e9.", "description_en": "This control ensures the ongoing monitoring of system activities to detect, respond to, and mitigate security threats.", "type": "technological", "category": "technical"}, {"ref": "A.8.17", "theme": "", "theme_en": "", "mesure": "Synchronisation des horloges", "mesure_en": "Clock synchronization", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les horloges des syst\u00e8mes sont synchronis\u00e9es pour maintenir des horodatages pr\u00e9cis et coh\u00e9rents pour les journaux et d'autres processus critiques.", "description_en": "This control ensures system clocks are synchronized to maintain accurate and consistent timestamps for logs and other critical processes.", "type": "technological", "category": "technical"}, {"ref": "A.8.18", "theme": "", "theme_en": "", "mesure": "Utilisation de programmes utilitaires \u00e0 privil\u00e8ges", "mesure_en": "Use of privileged utility programs", "description": "Cette mesure de s\u00e9curit\u00e9 restreint et surveille l'utilisation des programmes utilitaires privil\u00e9gi\u00e9s pour pr\u00e9venir les abus et les actions non autoris\u00e9es.", "description_en": "This control restricts and monitors the use of privileged utility programs to prevent misuse and unauthorized actions.", "type": "technological", "category": "technical"}, {"ref": "A.8.19", "theme": "", "theme_en": "", "mesure": "Installation de logiciels sur des syst\u00e8mes op\u00e9rationnels", "mesure_en": "Installation of software on operational systems", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que l'installation de logiciels sur les syst\u00e8mes op\u00e9rationnels est g\u00e9r\u00e9e de mani\u00e8re s\u00e9curis\u00e9e pour \u00e9viter les vuln\u00e9rabilit\u00e9s ou les modifications non autoris\u00e9es.", "description_en": "This control ensures software installation on operational systems is managed securely to prevent vulnerabilities or unauthorized changes.", "type": "technological", "category": "technical"}, {"ref": "A.8.20", "theme": "", "theme_en": "", "mesure": "S\u00e9curit\u00e9 des r\u00e9seaux", "mesure_en": "Networks security", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la s\u00e9curit\u00e9 du r\u00e9seau gr\u00e2ce \u00e0 des pare-feu, des syst\u00e8mes de d\u00e9tection d'intrusion et des contr\u00f4les d'acc\u00e8s pour prot\u00e9ger contre les acc\u00e8s non autoris\u00e9s et les attaques.", "description_en": "This control ensures network security through firewalls, intrusion detection systems, and access controls to protect against unauthorized access and attacks.", "type": "technological", "category": "technical"}, {"ref": "A.8.21", "theme": "", "theme_en": "", "mesure": "S\u00e9curit\u00e9 des services r\u00e9seau", "mesure_en": "Security of network services", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les services r\u00e9seau sont prot\u00e9g\u00e9s pour maintenir la confidentialit\u00e9, l'int\u00e9grit\u00e9 et la disponibilit\u00e9 pendant leur utilisation.", "description_en": "This control ensures network services are protected to maintain confidentiality, integrity, and availability during use.", "type": "technological", "category": "technical"}, {"ref": "A.8.22", "theme": "", "theme_en": "", "mesure": "Cloisonnement des r\u00e9seaux", "mesure_en": "Segregation of networks", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre la segmentation des r\u00e9seaux pour limiter la propagation des menaces et minimiser l'impact des violations potentielles.", "description_en": "This control implements network segregation to limit the spread of threats and minimize the impact of potential breaches.", "type": "technological", "category": "technical"}, {"ref": "A.8.23", "theme": "", "theme_en": "", "mesure": "Filtrage web", "mesure_en": "Web filtering", "description": "Cette mesure de s\u00e9curit\u00e9 utilise des outils de filtrage Web pour bloquer le contenu non autoris\u00e9 ou nuisible accessible sur Internet.", "description_en": "This control uses web filtering tools to block unauthorized or harmful content from being accessed over the internet.", "type": "technological", "category": "technical"}, {"ref": "A.8.24", "theme": "", "theme_en": "", "mesure": "Utilisation de la cryptographie", "mesure_en": "Use of cryptography", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que des techniques cryptographiques sont appliqu\u00e9es pour prot\u00e9ger la confidentialit\u00e9, l'int\u00e9grit\u00e9 et l'authenticit\u00e9 des donn\u00e9es.", "description_en": "This control ensures cryptographic techniques are applied to protect data confidentiality, integrity, and authenticity.", "type": "technological", "category": "technical"}, {"ref": "A.8.25", "theme": "", "theme_en": "", "mesure": "Cycle de vie de d\u00e9veloppement s\u00e9curis\u00e9", "mesure_en": "Secure development life cycle", "description": "Cette mesure de s\u00e9curit\u00e9 int\u00e8gre la s\u00e9curit\u00e9 \u00e0 toutes les \u00e9tapes du cycle de vie du d\u00e9veloppement pour garantir que les syst\u00e8mes et applications sont construits de mani\u00e8re s\u00e9curis\u00e9e.", "description_en": "This control integrates security into all stages of the development life cycle to ensure systems and applications are built securely.", "type": "technological", "category": "technical"}, {"ref": "A.8.26", "theme": "", "theme_en": "", "mesure": "Exigences de s\u00e9curit\u00e9 des applications", "mesure_en": "Application security requirements", "description": "Cette mesure de s\u00e9curit\u00e9 d\u00e9finit et applique des exigences de s\u00e9curit\u00e9 pour les applications afin de prot\u00e9ger contre les vuln\u00e9rabilit\u00e9s.", "description_en": "This control defines and enforces security requirements for applications to safeguard against vulnerabilities.", "type": "technological", "category": "technical"}, {"ref": "A.8.27", "theme": "", "theme_en": "", "mesure": "Principes d'ing\u00e9nierie et d'architecture des syst\u00e8mes s\u00e9curis\u00e9s", "mesure_en": "Secure system architecture and engineering principles", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que des principes de conception s\u00e9curis\u00e9s sont adopt\u00e9s lors du d\u00e9veloppement des architectures syst\u00e8me.", "description_en": "This control ensures secure design principles are adopted during the development of system architectures.", "type": "technological", "category": "technical"}, {"ref": "A.8.28", "theme": "", "theme_en": "", "mesure": "Codage s\u00e9curis\u00e9", "mesure_en": "Secure coding", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre des pratiques de codage s\u00e9curis\u00e9 pour minimiser les vuln\u00e9rabilit\u00e9s des logiciels d\u00e9velopp\u00e9s.", "description_en": "This control implements secure coding practices to minimize vulnerabilities in developed software.", "type": "technological", "category": "technical"}, {"ref": "A.8.29", "theme": "", "theme_en": "", "mesure": "Tests de s\u00e9curit\u00e9 dans le d\u00e9veloppement et l'acceptation", "mesure_en": "Security testing in development and acceptance", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que des tests de s\u00e9curit\u00e9 sont effectu\u00e9s pendant les phases de d\u00e9veloppement et d'acceptation pour identifier les faiblesses.", "description_en": "This control ensures security testing is conducted during development and acceptance phases to identify weaknesses.", "type": "technological", "category": "technical"}, {"ref": "A.8.30", "theme": "", "theme_en": "", "mesure": "D\u00e9veloppement externalis\u00e9", "mesure_en": "Outsourced development", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les risques de s\u00e9curit\u00e9 sont g\u00e9r\u00e9s efficacement lorsque le d\u00e9veloppement est externalis\u00e9 \u00e0 des fournisseurs tiers.", "description_en": "This control ensures security risks are managed effectively when development is outsourced to third-party vendors.", "type": "technological", "category": "technical"}, {"ref": "A.8.31", "theme": "", "theme_en": "", "mesure": "S\u00e9paration des environnements de d\u00e9veloppement, de test et op\u00e9rationnels", "mesure_en": "Separation of development, test and production environments", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les environnements de d\u00e9veloppement, de test et de production sont s\u00e9par\u00e9s pour \u00e9viter les interactions involontaires et les acc\u00e8s non autoris\u00e9s.", "description_en": "This control ensures development, test, and production environments are segregated to prevent unintended interactions and unauthorized access.", "type": "technological", "category": "technical"}, {"ref": "A.8.32", "theme": "", "theme_en": "", "mesure": "Gestion des changements", "mesure_en": "Change management", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les modifications des syst\u00e8mes sont g\u00e9r\u00e9es de mani\u00e8re s\u00e9curis\u00e9e pour minimiser les risques et maintenir la stabilit\u00e9 op\u00e9rationnelle.", "description_en": "This control ensures changes to systems are managed securely to minimize risks and maintain operational stability.", "type": "technological", "category": "technical"}, {"ref": "A.8.33", "theme": "", "theme_en": "", "mesure": "Informations de test", "mesure_en": "Test information", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge les donn\u00e9es de test pour \u00e9viter l'exposition d'informations sensibles ou confidentielles lors des processus de test.", "description_en": "This control protects test data to prevent the exposure of sensitive or confidential information during testing processes.", "type": "technological", "category": "technical"}, {"ref": "A.8.34", "theme": "", "theme_en": "", "mesure": "Protection des syst\u00e8mes d'information pendant les tests d'audit", "mesure_en": "Protection of information systems during audit testing", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les syst\u00e8mes et les donn\u00e9es sont prot\u00e9g\u00e9s pendant les audits en emp\u00eachant les acc\u00e8s non autoris\u00e9s, les fuites de donn\u00e9es ou les perturbations. Les mesures incluent l'utilisation d'environnements non productifs, des restrictions d'acc\u00e8s et des accords de confidentialit\u00e9 pour pr\u00e9server la s\u00e9curit\u00e9 et l'int\u00e9grit\u00e9 des syst\u00e8mes.", "description_en": "This control ensures that systems and data are safeguarded during audits by preventing unauthorized access, data leakage, or disruptions. Measures include using non-production environments, access restrictions, and confidentiality agreements to maintain system security and integrity.", "type": "technological", "category": "technical"}], "reference_controls": [{"ref": "A.5.1", "mesure": "Politiques de s\u00e9curit\u00e9 de l'information", "mesure_en": "Policies for information security", "description": "Cette mesure de s\u00e9curit\u00e9 \u00e9tablit et maintient des politiques de s\u00e9curit\u00e9 de l'information align\u00e9es sur les objectifs organisationnels. Les mesures incluent la d\u00e9finition de la port\u00e9e, la fixation des objectifs et l'alignement avec les exigences de conformit\u00e9.", "description_en": "This control establishes and maintains information security policies aligned with organizational objectives. Measures include defining scope, setting goals, and ensuring alignment with compliance requirements.", "category": "policy", "type": "organisationnel"}, {"ref": "A.5.2", "mesure": "Fonctions et responsabilit\u00e9s li\u00e9es \u00e0 la s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security roles and responsibilities", "description": "Cette mesure de s\u00e9curit\u00e9 d\u00e9finit et attribue des r\u00f4les et responsabilit\u00e9s en mati\u00e8re de s\u00e9curit\u00e9 de l'information pour garantir la responsabilit\u00e9. Les mesures incluent une documentation claire des responsabilit\u00e9s, des revues p\u00e9riodiques et des m\u00e9canismes d'application.", "description_en": "This control defines and assigns roles and responsibilities for information security to ensure accountability. Measures include clear documentation of responsibilities, periodic reviews, and enforcement mechanisms.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.3", "mesure": "S\u00e9paration des t\u00e2ches", "mesure_en": "Segregation of duties", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la s\u00e9paration des t\u00e2ches pour r\u00e9duire le risque d'erreurs, de fraude et d'acc\u00e8s non autoris\u00e9. Les mesures incluent la s\u00e9paration des r\u00f4les, des restrictions d'acc\u00e8s et des audits r\u00e9guliers.", "description_en": "This control ensures segregation of duties to reduce the risk of errors, fraud, and unauthorized access. Measures include role separation, access restrictions, and regular audits.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.4", "mesure": "Responsabilit\u00e9s de la direction", "mesure_en": "Management responsibilities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les responsabilit\u00e9s de gestion en mati\u00e8re de s\u00e9curit\u00e9 de l'information sont clairement d\u00e9finies et mises en \u0153uvre. Les mesures incluent la fixation d'objectifs, l'allocation de ressources et la supervision de la conformit\u00e9.", "description_en": "This control ensures management responsibilities for information security are clearly defined and implemented. Measures include setting objectives, allocating resources, and overseeing compliance.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.5", "mesure": "Contact avec les autorit\u00e9s", "mesure_en": "Contact with authorities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit une communication rapide avec les autorit\u00e9s comp\u00e9tentes en cas d'incidents de s\u00e9curit\u00e9 de l'information. Les mesures incluent des protocoles de contact, des listes de contacts \u00e0 jour et l'attribution de responsabilit\u00e9s.", "description_en": "This control ensures timely communication with relevant authorities during information security incidents. Measures include establishing contact protocols, maintaining updated contact lists, and assigning responsibilities.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.6", "mesure": "Contact avec des groupes d'int\u00e9r\u00eat sp\u00e9cifiques", "mesure_en": "Contact with special interest groups", "description": "Cette mesure de s\u00e9curit\u00e9 facilite le contact avec des groupes d'int\u00e9r\u00eat pour rester inform\u00e9 des tendances et pratiques en mati\u00e8re de s\u00e9curit\u00e9. Les mesures incluent la participation \u00e0 des forums, des adh\u00e9sions et des initiatives collaboratives.", "description_en": "This control facilitates contact with special interest groups to stay informed about security trends and practices. Measures include participation in forums, memberships, and collaborative initiatives.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.7", "mesure": "Renseignements sur les menaces", "mesure_en": "Threat intelligence", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que des renseignements sur les menaces sont d\u00e9velopp\u00e9s et maintenus pour identifier et att\u00e9nuer les risques de s\u00e9curit\u00e9. Les mesures incluent le suivi des flux de menaces, l'analyse des tendances et le partage d'informations exploitables.", "description_en": "This control ensures threat intelligence is developed and maintained to identify and mitigate security risks. Measures include monitoring threat feeds, analyzing trends, and sharing actionable insights.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.8", "mesure": "S\u00e9curit\u00e9 de l'information dans la gestion de projet", "mesure_en": "Information security in project management", "description": "Cette mesure de s\u00e9curit\u00e9 int\u00e8gre la s\u00e9curit\u00e9 de l'information dans les pratiques de gestion de projet. Les mesures incluent les \u00e9valuations des risques, les revues de conformit\u00e9 et les points de contr\u00f4le de s\u00e9curit\u00e9 tout au long du cycle de vie du projet.", "description_en": "This control incorporates information security into project management practices. Measures include risk assessments, compliance reviews, and security checkpoints during project lifecycles.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.9", "mesure": "Inventaire des informations et autres actifs associ\u00e9s", "mesure_en": "Inventory of information and other associated assets", "description": "Cette mesure de s\u00e9curit\u00e9 garantit qu\u2019un inventaire pr\u00e9cis des informations et des actifs associ\u00e9s est maintenu. Les mesures incluent le suivi des actifs, des audits p\u00e9riodiques et une classification par sensibilit\u00e9.", "description_en": "This control ensures an accurate inventory of information and associated assets is maintained. Measures include asset tracking, periodic audits, and classification by sensitivity.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.10", "mesure": "Utilisation correcte des informations et autres actifs associ\u00e9s", "mesure_en": "Acceptable use of information and other associated assets", "description": "Cette mesure de s\u00e9curit\u00e9 d\u00e9finit les r\u00e8gles d'utilisation acceptable des informations et des actifs associ\u00e9s pour assurer une manipulation appropri\u00e9e. Les mesures incluent des politiques document\u00e9es, la formation des utilisateurs et des m\u00e9canismes d'application.", "description_en": "This control defines acceptable use of information and associated assets to ensure proper handling. Measures include documented policies, user training, and enforcement mechanisms.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.11", "mesure": "Restitution des actifs", "mesure_en": "Return of assets", "description": "Cette mesure de s\u00e9curit\u00e9 garantit le retour s\u00e9curis\u00e9 des actifs lorsque des employ\u00e9s ou des sous-traitants quittent ou changent de r\u00f4le. Les mesures incluent des listes de contr\u00f4le, le suivi des actifs et des protocoles de d\u00e9sactivation.", "description_en": "This control ensures the secure return of assets when employees or contractors leave or change roles. Measures include checklists, asset tracking, and decommissioning protocols.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.12", "mesure": "Classification des informations", "mesure_en": "Classification of information", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les informations sont class\u00e9es en fonction de leur sensibilit\u00e9 et de leur valeur pour assurer une protection ad\u00e9quate. Les mesures incluent des sch\u00e9mas de classification, des restrictions d'acc\u00e8s et des directives d'\u00e9tiquetage.", "description_en": "This control ensures information is classified based on its sensitivity and value to ensure appropriate protection. Measures include classification schemes, access restrictions, and labeling guidelines.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.13", "mesure": "Marquage des informations", "mesure_en": "Labelling of information", "description": "Cette mesure de s\u00e9curit\u00e9 garantit un \u00e9tiquetage coh\u00e9rent des informations pour refl\u00e9ter leur classification et leurs exigences de traitement. Les mesures incluent des mod\u00e8les standardis\u00e9s, des formations et des audits.", "description_en": "This control ensures consistent labeling of information to reflect its classification and handling requirements. Measures include standardized templates, training, and audits.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.14", "mesure": "Transfert des informations", "mesure_en": "Information transfer", "description": "Cette mesure de s\u00e9curit\u00e9 \u00e9tablit des processus s\u00e9curis\u00e9s pour le transfert d'informations entre syst\u00e8mes ou organisations. Les mesures incluent le chiffrement, les contr\u00f4les d'acc\u00e8s et les protocoles de transfert s\u00e9curis\u00e9s.", "description_en": "This control establishes secure processes for transferring information between systems or organizations. Measures include encryption, access controls, and secure transfer protocols.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.15", "mesure": "Contr\u00f4le d'acc\u00e8s", "mesure_en": "Access control", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre et maintient des m\u00e9canismes de contr\u00f4le d'acc\u00e8s pour limiter l'acc\u00e8s aux individus autoris\u00e9s. Les mesures incluent des contr\u00f4les bas\u00e9s sur les r\u00f4les, l'authentification multifacteur et des revues p\u00e9riodiques.", "description_en": "This control implements and maintains access control mechanisms to restrict access to authorized individuals. Measures include role-based access, multi-factor authentication, and periodic reviews.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.16", "mesure": "Gestion des identit\u00e9s", "mesure_en": "Identity management", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les identit\u00e9s sont g\u00e9r\u00e9es de mani\u00e8re s\u00e9curis\u00e9e pour garantir un acc\u00e8s pr\u00e9cis et fiable aux syst\u00e8mes. Les mesures incluent la v\u00e9rification d'identit\u00e9, la gestion du cycle de vie et l'approvisionnement des acc\u00e8s.", "description_en": "This control ensures identities are managed securely to guarantee accurate and reliable access to systems. Measures include identity verification, lifecycle management, and access provisioning.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.17", "mesure": "Informations d'authentification", "mesure_en": "Authentication information", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge les informations d'authentification, telles que les mots de passe, pour emp\u00eacher tout acc\u00e8s non autoris\u00e9. Les mesures incluent le chiffrement, le stockage s\u00e9curis\u00e9 et les mises \u00e0 jour p\u00e9riodiques des mots de passe.", "description_en": "This control protects authentication information, such as passwords, to prevent unauthorized access. Measures include encryption, secure storage, and periodic password updates.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.18", "mesure": "Droits d'acc\u00e8s", "mesure_en": "Access rights", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les droits d'acc\u00e8s sont r\u00e9guli\u00e8rement revus et g\u00e9r\u00e9s pour s'aligner sur les r\u00f4les et responsabilit\u00e9s. Les mesures incluent des audits p\u00e9riodiques, la r\u00e9vocation des acc\u00e8s et la gestion automatis\u00e9e des acc\u00e8s.", "description_en": "This control ensures access rights are regularly reviewed and managed to align with roles and responsibilities. Measures include periodic audits, access revocation, and automated access management.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.19", "mesure": "S\u00e9curit\u00e9 de l'information dans les relations avec les fournisseurs", "mesure_en": "Information security in supplier relationships", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que la s\u00e9curit\u00e9 de l'information est int\u00e9gr\u00e9e dans les relations et processus avec les fournisseurs. Les mesures incluent la diligence raisonnable, les revues de s\u00e9curit\u00e9 et la surveillance continue.", "description_en": "This control ensures information security is embedded in supplier relationships and processes. Measures include due diligence, security reviews, and ongoing monitoring.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.20", "mesure": "La s\u00e9curit\u00e9 de l'information dans les accords conclus avec les fournisseurs", "mesure_en": "Addressing information security within supplier agreements", "description": "Cette mesure de s\u00e9curit\u00e9 aborde les exigences de s\u00e9curit\u00e9 de l'information dans les accords avec les fournisseurs. Les mesures incluent des clauses contractuelles explicites, des audits de conformit\u00e9 et des p\u00e9nalit\u00e9s d\u00e9finies pour les violations.", "description_en": "This control addresses information security requirements within supplier agreements. Measures include explicit contract clauses, compliance audits, and defined penalties for violations.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.21", "mesure": "Gestion de la s\u00e9curit\u00e9 de l'information dans la cha\u00eene d'approvisionnement des technologies de l'information et de la communication (TIC)", "mesure_en": "Managing information security in the ICT supply chain", "description": "Cette mesure de s\u00e9curit\u00e9 g\u00e8re les risques de s\u00e9curit\u00e9 de l'information dans la cha\u00eene d'approvisionnement TIC pour garantir la s\u00e9curit\u00e9 des services et des composants. Les mesures incluent des \u00e9valuations des risques, des \u00e9valuations des fournisseurs et des protocoles de r\u00e9ponse aux incidents.", "description_en": "This control manages information security risks in the ICT supply chain to ensure security of services and components. Measures include risk assessments, supplier evaluations, and incident response protocols.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.22", "mesure": "Surveillance, r\u00e9vision et gestion des changements des services fournisseurs", "mesure_en": "Monitor, review and change management of supplier services", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les services des fournisseurs sont surveill\u00e9s, revus et ajust\u00e9s pour maintenir la s\u00e9curit\u00e9 de l'information. Les mesures incluent des accords de niveau de service, des revues p\u00e9riodiques et des mises \u00e0 jour contractuelles.", "description_en": "This control ensures supplier services are monitored, reviewed, and adjusted to maintain information security. Measures include service level agreements, periodic reviews, and contract updates.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.23", "mesure": "S\u00e9curit\u00e9 de l'information dans l'utilisation de services en nuage", "mesure_en": "Information security for use of cloud services", "description": "Cette mesure de s\u00e9curit\u00e9 garantit l'utilisation s\u00e9curis\u00e9e des services cloud en abordant les risques associ\u00e9s. Les mesures incluent le chiffrement des donn\u00e9es, les contr\u00f4les d'acc\u00e8s et les revues de conformit\u00e9 des fournisseurs.", "description_en": "This control ensures the secure use of cloud services by addressing associated risks. Measures include data encryption, access controls, and provider compliance reviews.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.24", "mesure": "Planification et pr\u00e9paration de la gestion des incidents de s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security incident management planning and preparation", "description": "Cette mesure de s\u00e9curit\u00e9 garantit une planification et une pr\u00e9paration ad\u00e9quates pour la gestion des incidents de s\u00e9curit\u00e9 de l'information. Les mesures incluent des plans de r\u00e9ponse aux incidents, des exercices de formation et des protocoles de communication.", "description_en": "This control ensures proper planning and preparation for managing information security incidents. Measures include incident response plans, training exercises, and communication protocols.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.25", "mesure": "\u00c9valuation des \u00e9v\u00e9nements de s\u00e9curit\u00e9 de l'information et prise de d\u00e9cision", "mesure_en": "Assessment and decision on information security events", "description": "Cette mesure de s\u00e9curit\u00e9 \u00e9tablit des processus pour \u00e9valuer et d\u00e9cider des actions li\u00e9es aux \u00e9v\u00e9nements de s\u00e9curit\u00e9 de l'information. Les mesures incluent l'analyse des causes profondes, l'\u00e9valuation des risques et des plans d'att\u00e9nuation.", "description_en": "This control establishes processes for assessing and deciding on actions related to information security events. Measures include root cause analysis, risk evaluation, and mitigation plans.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.26", "mesure": "R\u00e9ponse aux incidents de s\u00e9curit\u00e9 de l'information", "mesure_en": "Response to information security incidents", "description": "Cette mesure de s\u00e9curit\u00e9 garantit une r\u00e9ponse efficace aux incidents de s\u00e9curit\u00e9 de l'information pour minimiser l'impact et r\u00e9cup\u00e9rer rapidement. Les mesures incluent le signalement des incidents, des protocoles d'escalade et des strat\u00e9gies de confinement.", "description_en": "This control ensures effective response to information security incidents to minimize impact and recover quickly. Measures include incident reporting, escalation protocols, and containment strategies.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.27", "mesure": "Tirer des enseignements des incidents de s\u00e9curit\u00e9 de l'information", "mesure_en": "Learning from information security incidents", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les le\u00e7ons tir\u00e9es des incidents de s\u00e9curit\u00e9 de l'information sont document\u00e9es et mises en \u0153uvre pour am\u00e9liorer les processus. Les mesures incluent des revues post-incidents, des plans d'action et des mises \u00e0 jour des politiques.", "description_en": "This control ensures lessons learned from information security incidents are documented and implemented to improve processes. Measures include post-incident reviews, action plans, and policy updates.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.28", "mesure": "Collecte de preuves", "mesure_en": "Collection of evidence", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les preuves sont collect\u00e9es et conserv\u00e9es lors des incidents de s\u00e9curit\u00e9 pour soutenir les enqu\u00eates. Les mesures incluent des proc\u00e9dures de cha\u00eene de conservation, le stockage s\u00e9curis\u00e9 et les contr\u00f4les d'acc\u00e8s.", "description_en": "This control ensures evidence is collected and preserved during security incidents to support investigations. Measures include chain-of-custody procedures, secure storage, and access controls.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.29", "mesure": "S\u00e9curit\u00e9 de l'information pendant une perturbation", "mesure_en": "Information security during disruption", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que la s\u00e9curit\u00e9 de l'information est maintenue pendant les perturbations pour assurer la continuit\u00e9 des op\u00e9rations. Les mesures incluent des plans de contingence, des syst\u00e8mes de sauvegarde et des m\u00e9canismes de basculement.", "description_en": "This control ensures information security is maintained during disruptions to guarantee continuity of operations. Measures include contingency plans, backup systems, and failover mechanisms.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.30", "mesure": "Pr\u00e9paration des TIC la continuit\u00e9 d'activit\u00e9", "mesure_en": "ICT readiness for business continuity", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la pr\u00e9paration TIC pour la continuit\u00e9 des activit\u00e9s afin de minimiser les temps d'arr\u00eat pendant les perturbations. Les mesures incluent des tests de plans de reprise, des syst\u00e8mes redondants et des sites de reprise apr\u00e8s sinistre.", "description_en": "This control ensures ICT readiness for business continuity to minimize downtime during disruptions. Measures include testing recovery plans, redundant systems, and disaster recovery sites.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.31", "mesure": "Exigences l\u00e9gales, statutaires, r\u00e9glementaires et contractuelles", "mesure_en": "Legal, statutory, regulatory and contractual requirements", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la conformit\u00e9 aux exigences l\u00e9gales, r\u00e9glementaires et contractuelles en mati\u00e8re de s\u00e9curit\u00e9 de l'information. Les mesures incluent des revues de politiques, des audits et la documentation des preuves.", "description_en": "This control ensures compliance with legal, statutory, regulatory, and contractual information security requirements. Measures include policy reviews, audits, and evidence documentation.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.32", "mesure": "Droits de propri\u00e9t\u00e9 intellectuelle", "mesure_en": "Intellectual property rights", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la protection des droits de propri\u00e9t\u00e9 intellectuelle par des mesures de s\u00e9curit\u00e9 de l'information appropri\u00e9es. Les mesures incluent des restrictions d'acc\u00e8s, le chiffrement et des accords l\u00e9gaux.", "description_en": "This control ensures intellectual property rights are protected through appropriate information security measures. Measures include access restrictions, encryption, and legal agreements.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.33", "mesure": "Protection des enregistrements", "mesure_en": "Protection of records", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les enregistrements sont stock\u00e9s et prot\u00e9g\u00e9s de mani\u00e8re s\u00e9curis\u00e9e pour pr\u00e9venir toute perte ou acc\u00e8s non autoris\u00e9. Les mesures incluent des politiques de r\u00e9tention, un stockage s\u00e9curis\u00e9 et des contr\u00f4les d'acc\u00e8s.", "description_en": "This control ensures records are securely stored and protected to prevent loss or unauthorized access. Measures include retention policies, secure storage, and access controls.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.34", "mesure": "Protection de la vie priv\u00e9e et des donn\u00e9es \u00e0 caract\u00e8re personnel (DCP)", "mesure_en": "Privacy and protection of PII", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge la confidentialit\u00e9 et garantit le traitement s\u00e9curis\u00e9 des informations personnellement identifiables (PII). Les mesures incluent l'anonymisation, le chiffrement et la conformit\u00e9 aux lois sur la confidentialit\u00e9.", "description_en": "This control protects privacy and ensures the secure handling of personally identifiable information (PII). Measures include anonymization, encryption, and compliance with privacy laws.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.35", "mesure": "R\u00e9vision ind\u00e9pendante de la s\u00e9curit\u00e9 de l'information", "mesure_en": "Independent review of information security", "description": "Cette mesure de s\u00e9curit\u00e9 garantit des revues ind\u00e9pendantes de la s\u00e9curit\u00e9 de l'information pour \u00e9valuer l'efficacit\u00e9 et la conformit\u00e9. Les mesures incluent des audits externes, des \u00e9valuations des risques et des actions de suivi.", "description_en": "This control ensures independent reviews of information security to evaluate effectiveness and compliance. Measures include external audits, risk assessments, and follow-up actions.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.36", "mesure": "Conformit\u00e9 aux politiques, r\u00e8gles et normes de s\u00e9curit\u00e9 de l'information", "mesure_en": "Compliance with policies, rules and standards for information security", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la conformit\u00e9 \u00e0 toutes les politiques, r\u00e8gles et normes en mati\u00e8re de s\u00e9curit\u00e9 de l'information. Les mesures incluent des formations r\u00e9guli\u00e8res, des revues de politiques et des m\u00e9canismes d'application.", "description_en": "This control ensures compliance with all policies, rules, and standards for information security. Measures include regular training, policy reviews, and enforcement mechanisms.", "category": "process", "type": "organisationnel"}, {"ref": "A.5.37", "mesure": "Proc\u00e9dures d'exploitation document\u00e9es", "mesure_en": "Documented operating procedures", "description": "Cette mesure de s\u00e9curit\u00e9 d\u00e9veloppe et maintient des proc\u00e9dures op\u00e9rationnelles document\u00e9es pour garantir la coh\u00e9rence des pratiques de s\u00e9curit\u00e9. Les mesures incluent la documentation des processus, le contr\u00f4le des versions et l'accessibilit\u00e9.", "description_en": "This control develops and maintains documented operating procedures to ensure consistency in security practices. Measures include process documentation, version control, and accessibility.", "category": "process", "type": "organisationnel"}, {"ref": "A.6.1", "mesure": "S\u00e9lection des candidats", "mesure_en": "Screening", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la mise en \u0153uvre de processus de v\u00e9rification pour \u00e9valuer l'ad\u00e9quation des candidats avant leur embauche. Les mesures incluent des v\u00e9rifications des ant\u00e9c\u00e9dents, la v\u00e9rification d'identit\u00e9 et l'\u00e9valuation des qualifications pour r\u00e9duire les risques de s\u00e9curit\u00e9.", "description_en": "This control ensures the implementation of screening processes to verify the suitability of candidates before employment. Measures include background checks, identity verification, and assessment of qualifications to reduce security risks.", "category": "process", "type": "people"}, {"ref": "A.6.2", "mesure": "Termes et conditions du contrat de travail", "mesure_en": "Terms and conditions of employment", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les termes et conditions d'emploi incluent des responsabilit\u00e9s en mati\u00e8re de s\u00e9curit\u00e9 de l'information. Les mesures incluent des clauses explicites sur la confidentialit\u00e9, le respect des politiques et les cons\u00e9quences des violations.", "description_en": "This control ensures that terms and conditions of employment include information security responsibilities. Measures include explicit clauses about confidentiality, compliance with policies, and consequences for breaches.", "category": "process", "type": "people"}, {"ref": "A.6.3", "mesure": "Sensibilisation, enseignement et formation en s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security awareness, education and training", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les employ\u00e9s re\u00e7oivent une sensibilisation, une \u00e9ducation et une formation r\u00e9guli\u00e8res en mati\u00e8re de s\u00e9curit\u00e9 de l'information. Les mesures incluent des sessions de formation planifi\u00e9es, des programmes d'apprentissage en ligne et des exercices de phishing simul\u00e9s.", "description_en": "This control ensures that employees receive regular information security awareness, education, and training. Measures include scheduled training sessions, e-learning programs, and simulated phishing exercises.", "category": "process", "type": "people"}, {"ref": "A.6.4", "mesure": "Proc\u00e9dure disciplinaire", "mesure_en": "Disciplinary process", "description": "Cette mesure de s\u00e9curit\u00e9 \u00e9tablit un processus disciplinaire pour traiter les violations des politiques de s\u00e9curit\u00e9 de l'information. Les mesures incluent des lignes directrices claires, des proc\u00e9dures d'escalade et une application coh\u00e9rente pour maintenir la responsabilit\u00e9.", "description_en": "This control establishes a disciplinary process to address breaches of information security policies. Measures include clear guidelines, escalation procedures, and consistent enforcement to maintain accountability.", "category": "process", "type": "people"}, {"ref": "A.6.5", "mesure": "Responsabilit\u00e9s apr\u00e8s la fin ou le changement d'emploi", "mesure_en": "Responsibilities after termination or change of employment", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les responsabilit\u00e9s li\u00e9es \u00e0 la s\u00e9curit\u00e9 de l'information sont d\u00e9finies et appliqu\u00e9es apr\u00e8s la fin d\u2019un contrat ou un changement de r\u00f4le. Les mesures incluent la r\u00e9vocation des droits d'acc\u00e8s, la r\u00e9cup\u00e9ration des actifs de l'organisation et la r\u00e9alisation d'entretiens de sortie.", "description_en": "This control ensures that responsibilities related to information security are defined and enforced after termination or role changes. Measures include revoking access rights, collecting organizational assets, and conducting exit interviews.", "category": "process", "type": "people"}, {"ref": "A.6.6", "mesure": "Accords de confidentialit\u00e9 ou de non-divulgation", "mesure_en": "Confidentiality or non-disclosure agreements", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre des accords de confidentialit\u00e9 ou de non-divulgation pour prot\u00e9ger les informations sensibles. Les mesures incluent des accords sign\u00e9s au d\u00e9but de l'emploi, des rappels p\u00e9riodiques et l'application d'actions l\u00e9gales en cas de violations.", "description_en": "This control implements confidentiality or non-disclosure agreements to protect sensitive information. Measures include signed agreements at the start of employment, periodic reminders, and enforcement of legal actions in case of violations.", "category": "process", "type": "people"}, {"ref": "A.6.7", "mesure": "Travail \u00e0 distance", "mesure_en": "Remote working", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la gestion s\u00e9curis\u00e9e des risques li\u00e9s \u00e0 la s\u00e9curit\u00e9 de l'information pendant le t\u00e9l\u00e9travail. Les mesures incluent un acc\u00e8s s\u00e9curis\u00e9 aux syst\u00e8mes de l'entreprise, l'utilisation obligatoire de VPN et des politiques pour la gestion des donn\u00e9es sensibles \u00e0 distance.", "description_en": "This control ensures the secure management of information security risks during remote working. Measures include secure access to corporate systems, mandatory use of VPNs, and policies for handling sensitive data remotely.", "category": "process", "type": "people"}, {"ref": "A.6.8", "mesure": "D\u00e9claration des \u00e9v\u00e9nements de s\u00e9curit\u00e9 de l'information", "mesure_en": "Information security event reporting", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les employ\u00e9s peuvent signaler rapidement les \u00e9v\u00e9nements de s\u00e9curit\u00e9 de l'information. Les mesures incluent des canaux de signalement d'incidents, des campagnes de sensibilisation et des proc\u00e9dures de suivi pour enqu\u00eater et traiter les \u00e9v\u00e9nements signal\u00e9s.", "description_en": "This control ensures employees can promptly report information security events. Measures include incident reporting channels, awareness campaigns, and follow-up procedures to investigate and address reported events.", "category": "process", "type": "people"}, {"ref": "A.7.1", "mesure": "P\u00e9rim\u00e8tres de s\u00e9curit\u00e9 physique", "mesure_en": "Physical security perimeters", "description": "Cette mesure de s\u00e9curit\u00e9 \u00e9tablit des p\u00e9rim\u00e8tres de s\u00e9curit\u00e9 physique pour prot\u00e9ger les zones critiques contre les acc\u00e8s non autoris\u00e9s. Les mesures incluent des barri\u00e8res, des contr\u00f4les d'acc\u00e8s et des syst\u00e8mes de surveillance pour garantir que seules les personnes autoris\u00e9es peuvent entrer.", "description_en": "This control establishes physical security perimeters to protect critical areas from unauthorized access. Measures include barriers, access controls, and monitoring systems to ensure only authorized individuals can enter.", "category": "physical", "type": "physical"}, {"ref": "A.7.2", "mesure": "Les entr\u00e9es physiques", "mesure_en": "Physical entry", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les points d'entr\u00e9e physiques sont contr\u00f4l\u00e9s et surveill\u00e9s pour emp\u00eacher les acc\u00e8s non autoris\u00e9s. Les mesures incluent des syst\u00e8mes de badges, du personnel de s\u00e9curit\u00e9 et des registres des visiteurs.", "description_en": "This control ensures physical entry points are controlled and monitored to prevent unauthorized access. Measures include badge systems, security personnel, and visitor logs.", "category": "physical", "type": "physical"}, {"ref": "A.7.3", "mesure": "S\u00e9curisation des bureaux, des salles et des installations", "mesure_en": "Securing offices, rooms and facilities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les bureaux, les pi\u00e8ces et les installations sont s\u00e9curis\u00e9s pour prot\u00e9ger les informations et les ressources. Les mesures incluent des portes verrouill\u00e9es, des zones restreintes et des syst\u00e8mes de surveillance.", "description_en": "This control ensures that offices, rooms, and facilities are secured to protect information and resources. Measures include locked doors, restricted areas, and surveillance systems.", "category": "physical", "type": "physical"}, {"ref": "A.7.4", "mesure": "Surveillance de la s\u00e9curit\u00e9 physique", "mesure_en": "Physical security monitoring", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre une surveillance de la s\u00e9curit\u00e9 physique pour d\u00e9tecter et r\u00e9pondre rapidement aux menaces. Les mesures incluent des syst\u00e8mes de vid\u00e9osurveillance, des d\u00e9tecteurs de mouvement et des alertes en temps r\u00e9el.", "description_en": "This control implements physical security monitoring to detect and respond promptly to threats. Measures include CCTV systems, motion detectors, and real-time alerts.", "category": "physical", "type": "physical"}, {"ref": "A.7.5", "mesure": "Protection contre les menaces physiques et environnementales", "mesure_en": "Protecting against physical and environmental threats", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge les syst\u00e8mes et les ressources contre les menaces physiques et environnementales. Les mesures incluent des syst\u00e8mes de suppression d'incendie, des contr\u00f4les de temp\u00e9rature et des barri\u00e8res anti-inondation.", "description_en": "This control protects systems and resources from physical and environmental threats. Measures include fire suppression systems, temperature controls, and flood prevention barriers.", "category": "physical", "type": "physical"}, {"ref": "A.7.6", "mesure": "Travail dans les zones s\u00e9curis\u00e9es", "mesure_en": "Working In secure areas", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les zones s\u00e9curis\u00e9es sont g\u00e9r\u00e9es pour permettre l'acc\u00e8s uniquement aux personnes autoris\u00e9es. Les mesures incluent des syst\u00e8mes de contr\u00f4le d'acc\u00e8s, des escortes pour visiteurs et la surveillance des activit\u00e9s.", "description_en": "This control ensures that secure areas are managed to allow authorized access only. Measures include access control systems, visitor escorts, and activity monitoring.", "category": "physical", "type": "physical"}, {"ref": "A.7.7", "mesure": "Bureau propre et \u00e9cran vide", "mesure_en": "Clear desk and clear screen", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les informations sensibles ne sont pas laiss\u00e9es expos\u00e9es en adoptant des politiques de bureau propre et d'\u00e9cran clair. Les mesures incluent le verrouillage des documents sensibles et le verrouillage automatique des \u00e9crans en cas d'inutilisation.", "description_en": "This control ensures sensitive information is not left exposed by adopting clear desk and clear screen policies. Measures include locking sensitive documents away and auto-locking screens when not in use.", "category": "physical", "type": "physical"}, {"ref": "A.7.8", "mesure": "Emplacement et protection du mat\u00e9riel", "mesure_en": "Equipment siting and protection", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les \u00e9quipements sont positionn\u00e9s et prot\u00e9g\u00e9s pour pr\u00e9venir les acc\u00e8s non autoris\u00e9s ou les dommages. Les mesures incluent des montages s\u00e9curis\u00e9s, des armoires verrouill\u00e9es et des zones d'acc\u00e8s restreintes.", "description_en": "This control ensures that equipment is positioned and protected to prevent unauthorized access or damage. Measures include secure mounting, locked cabinets, and restricted access areas.", "category": "physical", "type": "physical"}, {"ref": "A.7.9", "mesure": "S\u00e9curit\u00e9 des actifs hors des locaux", "mesure_en": "Security of assets off-premises", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les actifs utilis\u00e9s ou stock\u00e9s hors des locaux sont s\u00e9curis\u00e9s pour maintenir leur confidentialit\u00e9 et leur int\u00e9grit\u00e9. Les mesures incluent le chiffrement, le transport s\u00e9curis\u00e9 et le suivi des acc\u00e8s.", "description_en": "This control ensures assets used or stored off-premises are secured to maintain confidentiality and integrity. Measures include encryption, secure transport, and access tracking.", "category": "physical", "type": "physical"}, {"ref": "A.7.10", "mesure": "Supports de stockage", "mesure_en": "Storage media", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge les supports de stockage pour emp\u00eacher tout acc\u00e8s ou alt\u00e9ration non autoris\u00e9. Les mesures incluent le stockage s\u00e9curis\u00e9, le chiffrement et les restrictions d'acc\u00e8s.", "description_en": "This control safeguards storage media to prevent unauthorized access or tampering. Measures include secure storage, encryption, and access restrictions.", "category": "physical", "type": "physical"}, {"ref": "A.7.11", "mesure": "Services supports", "mesure_en": "Supporting utilities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les utilitaires de soutien, tels que les syst\u00e8mes d'alimentation et de refroidissement, sont fiables et prot\u00e9g\u00e9s contre les perturbations. Les mesures incluent des syst\u00e8mes redondants et une s\u00e9curit\u00e9 physique.", "description_en": "This control ensures that supporting utilities, such as power and cooling systems, are reliable and protected from disruptions. Measures include redundant systems and physical security.", "category": "physical", "type": "physical"}, {"ref": "A.7.12", "mesure": "S\u00e9curit\u00e9 du c\u00e2blage", "mesure_en": "Cabling security", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les c\u00e2bles sont s\u00e9curis\u00e9s pour pr\u00e9venir toute interception ou tout dommage non autoris\u00e9. Les mesures incluent des conduits de protection, un \u00e9tiquetage appropri\u00e9 et un routage s\u00e9curis\u00e9.", "description_en": "This control ensures that cables are secured to prevent unauthorized interception or damage. Measures include protective conduits, proper labeling, and secure routing.", "category": "physical", "type": "physical"}, {"ref": "A.7.13", "mesure": "Maintenance du mat\u00e9riel", "mesure_en": "Equipment maintenance", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les \u00e9quipements sont maintenus pour assurer leur bon fonctionnement et pr\u00e9venir les pannes. Les mesures incluent un entretien r\u00e9gulier, des pratiques de maintenance s\u00e9curis\u00e9es et un acc\u00e8s r\u00e9serv\u00e9 au personnel autoris\u00e9.", "description_en": "This control ensures that equipment is maintained to guarantee proper functioning and prevent failures. Measures include regular servicing, secure maintenance practices, and authorized personnel access.", "category": "physical", "type": "physical"}, {"ref": "A.7.14", "mesure": "\u00c9limination ou recyclage s\u00e9curis\u00e9(e) du mat\u00e9riel", "mesure_en": "Secure disposal or re-use of equipment", "description": "Cette mesure de s\u00e9curit\u00e9 garantit l'\u00e9limination ou la r\u00e9utilisation s\u00e9curis\u00e9e des \u00e9quipements pour prot\u00e9ger les informations sensibles. Les mesures incluent la d\u00e9sinfection des donn\u00e9es, la destruction physique et les processus de mise au rebut certifi\u00e9s.", "description_en": "This control ensures the secure disposal or reuse of equipment to protect sensitive information. Measures include data sanitization, physical destruction, and certified disposal processes.", "category": "physical", "type": "physical"}, {"ref": "A.8.1", "mesure": "Terminaux finaux des utilisateurs", "mesure_en": "User end point devices", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la protection des dispositifs de point de terminaison tels que les ordinateurs portables, de bureau et les appareils mobiles en mettant en \u0153uvre des mesures comme la d\u00e9tection des terminaux, le chiffrement et des configurations s\u00e9curis\u00e9es pour minimiser les risques.", "description_en": "This control ensures the protection of endpoint devices such as laptops, desktops, and mobile devices by implementing security measures like endpoint detection, encryption, and secure configurations to minimize risks.", "category": "technical", "type": "technological"}, {"ref": "A.8.2", "mesure": "Droits d'acc\u00e8s privil\u00e9gi\u00e9s", "mesure_en": "Privileged access rights", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les droits d'acc\u00e8s privil\u00e9gi\u00e9s sont accord\u00e9s, g\u00e9r\u00e9s et surveill\u00e9s avec soin pour pr\u00e9venir les abus et renforcer la s\u00e9curit\u00e9. Les mesures comprennent des contr\u00f4les d'acc\u00e8s bas\u00e9s sur les r\u00f4les, des revues p\u00e9riodiques et une gestion stricte des comptes.", "description_en": "This control ensures that privileged access rights are granted, managed, and monitored carefully to prevent misuse and enhance security. Measures include role-based access controls, periodic reviews, and strict account management.", "category": "technical", "type": "technological"}, {"ref": "A.8.3", "mesure": "Restriction d'acc\u00e8s aux informations", "mesure_en": "Information access restriction", "description": "Cette mesure de s\u00e9curit\u00e9 limite l'acc\u00e8s aux informations sensibles selon le principe du besoin d'en conna\u00eetre. Les mesures incluent l'authentification des utilisateurs, les permissions bas\u00e9es sur les r\u00f4les et des revues r\u00e9guli\u00e8res des acc\u00e8s.", "description_en": "This control restricts access to sensitive information based on need-to-know principles. Measures include user authentication, role-based permissions, and regular access reviews.", "category": "technical", "type": "technological"}, {"ref": "A.8.4", "mesure": "Acc\u00e8s aux codes source", "mesure_en": "Access to source code", "description": "Cette mesure de s\u00e9curit\u00e9 s\u00e9curise l'acc\u00e8s au code source en emp\u00eachant la visualisation, la modification ou l'exposition non autoris\u00e9es. Les mesures incluent le contr\u00f4le de version, les d\u00e9p\u00f4ts s\u00e9curis\u00e9s et l'acc\u00e8s restreint aux d\u00e9veloppeurs.", "description_en": "This control secures access to source code by preventing unauthorized viewing, modification, or exposure. Measures include version control, secure repositories, and restricted developer access.", "category": "technical", "type": "technological"}, {"ref": "A.8.5", "mesure": "Authentification s\u00e9curis\u00e9e", "mesure_en": "Secure authentication", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre des m\u00e9canismes d'authentification solides, tels que l'authentification multifacteur, pour v\u00e9rifier l'identit\u00e9 des utilisateurs et emp\u00eacher les acc\u00e8s non autoris\u00e9s.", "description_en": "This control implements strong authentication mechanisms, such as multi-factor authentication, to verify user identities and prevent unauthorized access.", "category": "technical", "type": "technological"}, {"ref": "A.8.6", "mesure": "Dimensionnement", "mesure_en": "Capacity management", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que la capacit\u00e9 des syst\u00e8mes est g\u00e9r\u00e9e pour assurer des performances ad\u00e9quates et \u00e9viter les perturbations. Les mesures incluent la surveillance de l'utilisation des ressources et la planification des besoins futurs.", "description_en": "This control ensures system capacity is managed to provide adequate performance and prevent disruptions. Measures include monitoring resource usage and planning for future needs.", "category": "technical", "type": "technological"}, {"ref": "A.8.7", "mesure": "Protection contre les programmes malveillants (malware)", "mesure_en": "Protection against malware", "description": "Cette mesure de s\u00e9curit\u00e9 d\u00e9ploie des mesures comme des logiciels antivirus, des outils de d\u00e9tection des menaces et des mises \u00e0 jour r\u00e9guli\u00e8res pour prot\u00e9ger les syst\u00e8mes contre les logiciels malveillants et les attaques.", "description_en": "This control deploys measures like antivirus software, threat detection tools, and regular updates to protect systems from malware and malicious attacks.", "category": "technical", "type": "technological"}, {"ref": "A.8.8", "mesure": "Gestion des vuln\u00e9rabilit\u00e9s techniques", "mesure_en": "Management of technical vulnerabilities", "description": "Cette mesure de s\u00e9curit\u00e9 identifie, \u00e9value et rem\u00e9die rapidement aux vuln\u00e9rabilit\u00e9s techniques pour minimiser les risques de s\u00e9curit\u00e9. Les mesures incluent les analyses de vuln\u00e9rabilit\u00e9s et la gestion des correctifs.", "description_en": "This control identifies, evaluates, and remediates technical vulnerabilities promptly to minimize security risks. Measures include vulnerability scanning and patch management.", "category": "technical", "type": "technological"}, {"ref": "A.8.9", "mesure": "Gestion des configurations", "mesure_en": "Configuration management", "description": "Cette mesure de s\u00e9curit\u00e9 garantit une gestion coh\u00e9rente des configurations des syst\u00e8mes pour maintenir des param\u00e8tres s\u00e9curis\u00e9s et pr\u00e9venir les changements non autoris\u00e9s.", "description_en": "This control ensures consistent management of system configurations to maintain security settings and prevent unauthorized changes.", "category": "technical", "type": "technological"}, {"ref": "A.8.10", "mesure": "Suppression des informations", "mesure_en": "Information deletion", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les informations sensibles sont supprim\u00e9es de mani\u00e8re s\u00e9curis\u00e9e lorsqu'elles ne sont plus n\u00e9cessaires pour \u00e9viter toute r\u00e9cup\u00e9ration ou exposition non autoris\u00e9e.", "description_en": "This control ensures sensitive information is securely deleted when no longer required to prevent unauthorized recovery or exposure.", "category": "technical", "type": "technological"}, {"ref": "A.8.11", "mesure": "Masquage des donn\u00e9es", "mesure_en": "Data masking", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge les informations sensibles lors de leur traitement ou affichage en utilisant des techniques de masquage des donn\u00e9es pour les rendre inaccessibles aux utilisateurs non autoris\u00e9s.", "description_en": "This control protects sensitive information during processing or display by using data masking techniques to obscure data from unauthorized users.", "category": "technical", "type": "technological"}, {"ref": "A.8.12", "mesure": "Pr\u00e9vention de la fuite de donn\u00e9es", "mesure_en": "Data leakage prevention", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre des m\u00e9canismes pour emp\u00eacher l'exposition accidentelle des donn\u00e9es sensibles via des e-mails, des supports amovibles ou d'autres canaux.", "description_en": "This control implements mechanisms to prevent the accidental exposure of sensitive data through email, removable media, or other channels.", "category": "technical", "type": "technological"}, {"ref": "A.8.13", "mesure": "Sauvegarde des informations", "mesure_en": "Information backup", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les informations critiques sont sauvegard\u00e9es r\u00e9guli\u00e8rement et en toute s\u00e9curit\u00e9 pour assurer leur disponibilit\u00e9 en cas d'incidents ou de catastrophes.", "description_en": "This control ensures critical information is backed up regularly and securely to ensure its availability in case of incidents or disasters.", "category": "technical", "type": "technological"}, {"ref": "A.8.14", "mesure": "Redondance des moyens de traitement de l'information", "mesure_en": "Redundancy of information processing facilities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que la redondance est int\u00e9gr\u00e9e dans les installations de traitement pour maintenir la disponibilit\u00e9 et les op\u00e9rations en cas de d\u00e9faillances ou d'urgences.", "description_en": "This control ensures redundancy is built into processing facilities to maintain availability and operations during system failures or emergencies.", "category": "technical", "type": "technological"}, {"ref": "A.8.15", "mesure": "Journalisation", "mesure_en": "Logging", "description": "Cette mesure de s\u00e9curit\u00e9 permet la journalisation des activit\u00e9s au sein des syst\u00e8mes pour soutenir la surveillance, la d\u00e9tection des incidents et les analyses forensiques.", "description_en": "This control enables logging of activities within systems to support monitoring, incident detection, and forensic investigations.", "category": "technical", "type": "technological"}, {"ref": "A.8.16", "mesure": "Activit\u00e9s de surveillance", "mesure_en": "Monitoring activities", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la surveillance continue des activit\u00e9s du syst\u00e8me pour d\u00e9tecter, r\u00e9pondre et att\u00e9nuer les menaces \u00e0 la s\u00e9curit\u00e9.", "description_en": "This control ensures the ongoing monitoring of system activities to detect, respond to, and mitigate security threats.", "category": "technical", "type": "technological"}, {"ref": "A.8.17", "mesure": "Synchronisation des horloges", "mesure_en": "Clock synchronization", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les horloges des syst\u00e8mes sont synchronis\u00e9es pour maintenir des horodatages pr\u00e9cis et coh\u00e9rents pour les journaux et d'autres processus critiques.", "description_en": "This control ensures system clocks are synchronized to maintain accurate and consistent timestamps for logs and other critical processes.", "category": "technical", "type": "technological"}, {"ref": "A.8.18", "mesure": "Utilisation de programmes utilitaires \u00e0 privil\u00e8ges", "mesure_en": "Use of privileged utility programs", "description": "Cette mesure de s\u00e9curit\u00e9 restreint et surveille l'utilisation des programmes utilitaires privil\u00e9gi\u00e9s pour pr\u00e9venir les abus et les actions non autoris\u00e9es.", "description_en": "This control restricts and monitors the use of privileged utility programs to prevent misuse and unauthorized actions.", "category": "technical", "type": "technological"}, {"ref": "A.8.19", "mesure": "Installation de logiciels sur des syst\u00e8mes op\u00e9rationnels", "mesure_en": "Installation of software on operational systems", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que l'installation de logiciels sur les syst\u00e8mes op\u00e9rationnels est g\u00e9r\u00e9e de mani\u00e8re s\u00e9curis\u00e9e pour \u00e9viter les vuln\u00e9rabilit\u00e9s ou les modifications non autoris\u00e9es.", "description_en": "This control ensures software installation on operational systems is managed securely to prevent vulnerabilities or unauthorized changes.", "category": "technical", "type": "technological"}, {"ref": "A.8.20", "mesure": "S\u00e9curit\u00e9 des r\u00e9seaux", "mesure_en": "Networks security", "description": "Cette mesure de s\u00e9curit\u00e9 garantit la s\u00e9curit\u00e9 du r\u00e9seau gr\u00e2ce \u00e0 des pare-feu, des syst\u00e8mes de d\u00e9tection d'intrusion et des contr\u00f4les d'acc\u00e8s pour prot\u00e9ger contre les acc\u00e8s non autoris\u00e9s et les attaques.", "description_en": "This control ensures network security through firewalls, intrusion detection systems, and access controls to protect against unauthorized access and attacks.", "category": "technical", "type": "technological"}, {"ref": "A.8.21", "mesure": "S\u00e9curit\u00e9 des services r\u00e9seau", "mesure_en": "Security of network services", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les services r\u00e9seau sont prot\u00e9g\u00e9s pour maintenir la confidentialit\u00e9, l'int\u00e9grit\u00e9 et la disponibilit\u00e9 pendant leur utilisation.", "description_en": "This control ensures network services are protected to maintain confidentiality, integrity, and availability during use.", "category": "technical", "type": "technological"}, {"ref": "A.8.22", "mesure": "Cloisonnement des r\u00e9seaux", "mesure_en": "Segregation of networks", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre la segmentation des r\u00e9seaux pour limiter la propagation des menaces et minimiser l'impact des violations potentielles.", "description_en": "This control implements network segregation to limit the spread of threats and minimize the impact of potential breaches.", "category": "technical", "type": "technological"}, {"ref": "A.8.23", "mesure": "Filtrage web", "mesure_en": "Web filtering", "description": "Cette mesure de s\u00e9curit\u00e9 utilise des outils de filtrage Web pour bloquer le contenu non autoris\u00e9 ou nuisible accessible sur Internet.", "description_en": "This control uses web filtering tools to block unauthorized or harmful content from being accessed over the internet.", "category": "technical", "type": "technological"}, {"ref": "A.8.24", "mesure": "Utilisation de la cryptographie", "mesure_en": "Use of cryptography", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que des techniques cryptographiques sont appliqu\u00e9es pour prot\u00e9ger la confidentialit\u00e9, l'int\u00e9grit\u00e9 et l'authenticit\u00e9 des donn\u00e9es.", "description_en": "This control ensures cryptographic techniques are applied to protect data confidentiality, integrity, and authenticity.", "category": "technical", "type": "technological"}, {"ref": "A.8.25", "mesure": "Cycle de vie de d\u00e9veloppement s\u00e9curis\u00e9", "mesure_en": "Secure development life cycle", "description": "Cette mesure de s\u00e9curit\u00e9 int\u00e8gre la s\u00e9curit\u00e9 \u00e0 toutes les \u00e9tapes du cycle de vie du d\u00e9veloppement pour garantir que les syst\u00e8mes et applications sont construits de mani\u00e8re s\u00e9curis\u00e9e.", "description_en": "This control integrates security into all stages of the development life cycle to ensure systems and applications are built securely.", "category": "technical", "type": "technological"}, {"ref": "A.8.26", "mesure": "Exigences de s\u00e9curit\u00e9 des applications", "mesure_en": "Application security requirements", "description": "Cette mesure de s\u00e9curit\u00e9 d\u00e9finit et applique des exigences de s\u00e9curit\u00e9 pour les applications afin de prot\u00e9ger contre les vuln\u00e9rabilit\u00e9s.", "description_en": "This control defines and enforces security requirements for applications to safeguard against vulnerabilities.", "category": "technical", "type": "technological"}, {"ref": "A.8.27", "mesure": "Principes d'ing\u00e9nierie et d'architecture des syst\u00e8mes s\u00e9curis\u00e9s", "mesure_en": "Secure system architecture and engineering principles", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que des principes de conception s\u00e9curis\u00e9s sont adopt\u00e9s lors du d\u00e9veloppement des architectures syst\u00e8me.", "description_en": "This control ensures secure design principles are adopted during the development of system architectures.", "category": "technical", "type": "technological"}, {"ref": "A.8.28", "mesure": "Codage s\u00e9curis\u00e9", "mesure_en": "Secure coding", "description": "Cette mesure de s\u00e9curit\u00e9 met en \u0153uvre des pratiques de codage s\u00e9curis\u00e9 pour minimiser les vuln\u00e9rabilit\u00e9s des logiciels d\u00e9velopp\u00e9s.", "description_en": "This control implements secure coding practices to minimize vulnerabilities in developed software.", "category": "technical", "type": "technological"}, {"ref": "A.8.29", "mesure": "Tests de s\u00e9curit\u00e9 dans le d\u00e9veloppement et l'acceptation", "mesure_en": "Security testing in development and acceptance", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que des tests de s\u00e9curit\u00e9 sont effectu\u00e9s pendant les phases de d\u00e9veloppement et d'acceptation pour identifier les faiblesses.", "description_en": "This control ensures security testing is conducted during development and acceptance phases to identify weaknesses.", "category": "technical", "type": "technological"}, {"ref": "A.8.30", "mesure": "D\u00e9veloppement externalis\u00e9", "mesure_en": "Outsourced development", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les risques de s\u00e9curit\u00e9 sont g\u00e9r\u00e9s efficacement lorsque le d\u00e9veloppement est externalis\u00e9 \u00e0 des fournisseurs tiers.", "description_en": "This control ensures security risks are managed effectively when development is outsourced to third-party vendors.", "category": "technical", "type": "technological"}, {"ref": "A.8.31", "mesure": "S\u00e9paration des environnements de d\u00e9veloppement, de test et op\u00e9rationnels", "mesure_en": "Separation of development, test and production environments", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les environnements de d\u00e9veloppement, de test et de production sont s\u00e9par\u00e9s pour \u00e9viter les interactions involontaires et les acc\u00e8s non autoris\u00e9s.", "description_en": "This control ensures development, test, and production environments are segregated to prevent unintended interactions and unauthorized access.", "category": "technical", "type": "technological"}, {"ref": "A.8.32", "mesure": "Gestion des changements", "mesure_en": "Change management", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les modifications des syst\u00e8mes sont g\u00e9r\u00e9es de mani\u00e8re s\u00e9curis\u00e9e pour minimiser les risques et maintenir la stabilit\u00e9 op\u00e9rationnelle.", "description_en": "This control ensures changes to systems are managed securely to minimize risks and maintain operational stability.", "category": "technical", "type": "technological"}, {"ref": "A.8.33", "mesure": "Informations de test", "mesure_en": "Test information", "description": "Cette mesure de s\u00e9curit\u00e9 prot\u00e8ge les donn\u00e9es de test pour \u00e9viter l'exposition d'informations sensibles ou confidentielles lors des processus de test.", "description_en": "This control protects test data to prevent the exposure of sensitive or confidential information during testing processes.", "category": "technical", "type": "technological"}, {"ref": "A.8.34", "mesure": "Protection des syst\u00e8mes d'information pendant les tests d'audit", "mesure_en": "Protection of information systems during audit testing", "description": "Cette mesure de s\u00e9curit\u00e9 garantit que les syst\u00e8mes et les donn\u00e9es sont prot\u00e9g\u00e9s pendant les audits en emp\u00eachant les acc\u00e8s non autoris\u00e9s, les fuites de donn\u00e9es ou les perturbations. Les mesures incluent l'utilisation d'environnements non productifs, des restrictions d'acc\u00e8s et des accords de confidentialit\u00e9 pour pr\u00e9server la s\u00e9curit\u00e9 et l'int\u00e9grit\u00e9 des syst\u00e8mes.", "description_en": "This control ensures that systems and data are safeguarded during audits by preventing unauthorized access, data leakage, or disruptions. Measures include using non-production environments, access restrictions, and confidentiality agreements to maintain system security and integrity.", "category": "technical", "type": "technological"}]};
